INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('558e65db-f88f-5b73-8b8a-27642f8dfc45', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ما العلامة الجنسية الأوّلية للبلوغ؟', '[{"id":"a","text":"خشونة الصوت عند الفتى"},{"id":"b","text":"نموّ شعر العانة"},{"id":"c","text":"بدء الغدد التناسلية في إنتاج الأمشاج"},{"id":"d","text":"نموّ الثديين عند الفتاة"}]'::jsonb, 'c', 'العلامات الأوّلية ترتبط مباشرةً بوظيفة التكاثر، أي نضج الغدد التناسلية وبدئها في إنتاج الأمشاج (نطاف عند الفتى، بويضات عند الفتاة). أمّا خشونة الصوت ونموّ الشعر ونموّ الثديين فهي علامات ثانوية لا تنتج عنها أمشاج.', 1)
