INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f41ff6b-ba79-5c2f-b08d-da6f57a8877a', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ما المشيج الذي تنتجه الخصية؟', '[{"id":"a","text":"البويضة"},{"id":"b","text":"النطفة"},{"id":"c","text":"البيضة المخصّبة"},{"id":"d","text":"الهرمون"}]'::jsonb, 'b', 'الخصية هي الغدّة التناسلية الذكرية التي تنتج النطاف (المشيج الذكري). البويضة ينتجها المبيض، والبيضة المخصّبة تنتج عن اندماج المشيجين، والهرمون ليس مشيجًا بل مادّة كيميائية تنظّم الوظائف.', 2)
