INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('511d5dad-156c-553b-9592-81828f63aac6', '8da239ab-2d7d-58b4-810d-be40cba982da', 'أين يحدث الإلقاح عادةً عند المرأة؟', '[{"id":"a","text":"في المبيض"},{"id":"b","text":"في المهبل"},{"id":"c","text":"في الرحم"},{"id":"d","text":"في البوق (قناة فالوب)"}]'::jsonb, 'd', 'تلتقي النطفة بالبويضة فيحدث الإلقاح عادةً في البوق (قناة فالوب). المبيض يطلق البويضة فقط، والرحم مكان تعشيش البيضة المخصّبة ونموّ الجنين لاحقًا، والمهبل قناة الجماع والولادة.', 3)
