  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f955d3d3-c8d9-551c-bae9-e53357ad444f', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ماذا يدلّ نزول الطمث؟', '[{"id":"a","text":"على حدوث إلقاح في الدورة"},{"id":"b","text":"على بداية الحمل"},{"id":"c","text":"على عدم حدوث إلقاح فتساقطت بطانة الرحم"},{"id":"d","text":"على توقّف عمل المبيضين نهائيًّا"}]'::jsonb, 'c', 'تتكاثف بطانة الرحم استعدادًا لاستقبال بيضة مخصّبة؛ فإن لم يحدث إلقاح تتفكّك هذه البطانة وتنزل مع الدم = الطمث. لذلك الطمث دليل على عدم حدوث حمل في الدورة المنقضية، وليس دليل إلقاح أو حمل، ولا يعني توقّف المبيضين.', 5)
ON CONFLICT (id) DO UPDATE SET
