  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95c614a2-5e21-54bc-872d-4a3fd33636e3', '8da239ab-2d7d-58b4-810d-be40cba982da', 'كم عدد النطاف التي تندمج مع البويضة في الإلقاح؟', '[{"id":"a","text":"نطفة واحدة فقط"},{"id":"b","text":"نطفتان"},{"id":"c","text":"كلّ النطاف التي تصل إلى البويضة"},{"id":"d","text":"لا تندمج أيّ نطفة بل تكفي ملامستها"}]'::jsonb, 'a', 'تخترق نطفة واحدة فقط البويضة وتندمج معها، ثمّ تُغلَق البويضة أمام بقيّة النطاف. اندماج أكثر من نطفة لا ينتج بيضة سليمة، ومجرّد الملامسة دون اندماج لا يحقّق الإلقاح.', 6)
