  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40571775-c88f-503f-bc5e-41dee7862b91', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ما الاسم الذي يطلق على الخليّة الناتجة عن اندماج النطفة والبويضة؟', '[{"id":"a","text":"الجنين"},{"id":"b","text":"البيضة المخصّبة (اللاقحة)"},{"id":"c","text":"المشيمة"},{"id":"d","text":"الجُريب"}]'::jsonb, 'b', 'اندماج المشيجين ينتج البيضة المخصّبة (اللاقحة)، وهي أوّل خليّة للكائن الجديد. الجنين مرحلة لاحقة بعد انقسامات البيضة وتعشيشها، والمشيمة عضو تبادل بين الأمّ والجنين، والجُريب هو ما يحتوي البويضة داخل المبيض قبل الإباضة.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9756bae8-30cd-55e7-a0b2-3b6faeed1690', '8da239ab-2d7d-58b4-810d-be40cba982da', 'أيّ ممّا يلي ليس طريقًا لانتقال فيروس السيدا (VIH)؟', '[{"id":"a","text":"العلاقة الجنسية غير المحمية"},{"id":"b","text":"نقل دم ملوّث أو تبادل الإبر"},{"id":"c","text":"من الأمّ المصابة إلى جنينها"},{"id":"d","text":"مصافحة شخص مصاب أو مشاركته الطعام"}]'::jsonb, 'd', 'ينتقل فيروس السيدا عبر العلاقة الجنسية غير المحمية، والدم الملوّث (نقل الدم أو تبادل الإبر)، ومن الأمّ إلى جنينها. أمّا المصافحة ومشاركة الطعام والأواني والعطاس ولسعة البعوض فلا تنقل الفيروس، وهذا اعتقاد خاطئ شائع يسبّب وصم المصابين دون مبرّر علمي.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('22436c51-690e-519a-bacd-4a6c42949e57', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', 'تمرين: البلوغ والأجهزة التكاثرية', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a4f69d8-24fa-5b8c-877f-723f6638b509', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما البلوغ؟', '[{"id":"a","text":"مرحلة يصبح فيها الجسم قادرًا على التكاثر"},{"id":"b","text":"مرحلة تتوقّف فيها الغدد التناسلية عن العمل"},{"id":"c","text":"مرض يصيب المراهقين"},{"id":"d","text":"نهاية القدرة على الإنجاب"}]'::jsonb, 'a', 'البلوغ مرحلة انتقال من الطفولة إلى القدرة على التكاثر، تبدأ فيها الغدد التناسلية بإنتاج الأمشاج بتحكّم من الهرمونات الجنسية. فهو ليس مرضًا ولا توقّفًا للغدد، وهو بداية القدرة على الإنجاب لا نهايتها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0d4d9b4-ca0a-59fa-9d02-4ea585a1d10b', '22436c51-690e-519a-bacd-4a6c42949e57', 'أيّ ممّا يلي علامة جنسية ثانوية عند الفتاة؟', '[{"id":"a","text":"إنتاج البويضات"},{"id":"b","text":"نضج المبيض"},{"id":"c","text":"نموّ الثديين"},{"id":"d","text":"إطلاق البويضة عند الإباضة"}]'::jsonb, 'c', 'العلامات الثانوية تغيّرات ظاهرة لا تنتج عنها أمشاج، مثل نموّ الثديين. أمّا إنتاج البويضات ونضج المبيض والإباضة فعلامات أوّلية لأنّها ترتبط مباشرةً بوظيفة التكاثر وإنتاج الأمشاج.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6ea4f3d-b972-5f4f-bfa0-77090bf848e8', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما الغدّة التي تنتج النطاف عند الرجل؟', '[{"id":"a","text":"البروستاتا"},{"id":"b","text":"الخصية"},{"id":"c","text":"المبيض"},{"id":"d","text":"الحُويصلة المنوية"}]'::jsonb, 'b', 'الخصية هي الغدّة التناسلية التي تنتج النطاف. البروستاتا والحُويصلة المنوية غدّتان ملحقتان تفرزان السائل المنوي الذي يغذّي النطاف وينقلها، لا تنتجانها. أمّا المبيض فهو غدّة أنثوية تنتج البويضات.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('568f02ef-ada6-50b6-b1e0-9e53353b8e67', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما المشيج الذي ينتجه المبيض؟', '[{"id":"a","text":"النطفة"},{"id":"b","text":"السائل المنوي"},{"id":"c","text":"البويضة"},{"id":"d","text":"المشيمة"}]'::jsonb, 'c', 'المبيض غدّة أنثوية تنتج البويضة (المشيج الأنثوي) وتفرز الهرمونات الجنسية الأنثوية. النطفة مشيج ذكري تنتجه الخصية، والسائل المنوي إفراز ذكري، والمشيمة عضو يتكوّن أثناء الحمل وليست مشيجًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b5b04d0-f437-55ba-bc3c-df719663946c', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما العضو الذي يحتضن نموّ الجنين أثناء الحمل؟', '[{"id":"a","text":"المبيض"},{"id":"b","text":"الرحم"},{"id":"c","text":"البوق"},{"id":"d","text":"المهبل"}]'::jsonb, 'b', 'الرحم عضو عضليّ مجوّف تنغرس في بطانته البيضة المخصّبة ويحتضن نموّ الجنين طوال الحمل. المبيض ينتج البويضات، والبوق ينقل البويضة ويحدث فيه الإلقاح، والمهبل قناة الجماع والولادة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('363ccbdf-a9f1-556c-8676-07fa94fa6013', '22436c51-690e-519a-bacd-4a6c42949e57', 'أيّ خاصية تميّز النطفة عن البويضة؟', '[{"id":"a","text":"النطفة كبيرة وغير متحرّكة"},{"id":"b","text":"النطفة صغيرة ومتحرّكة بفضل سوطها"},{"id":"c","text":"النطفة تختزن مدّخرات غذائية كبيرة"},{"id":"d","text":"النطفة لا تحمل أيّ معلومة وراثية"}]'::jsonb, 'b', 'النطفة خليّة صغيرة جدًّا متحرّكة لها سوط (ذنب) يمكّنها من السباحة نحو البويضة. أمّا البويضة فهي الكبيرة غير المتحرّكة التي تختزن المدّخرات الغذائية. وكلا المشيجين يحمل نصف المعلومة الوراثية، فلا يصحّ أنّ النطفة لا تحمل معلومة وراثية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('089e735c-146a-5920-ace4-7460262de9b7', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', 'تمرين: الدورة الجنسية والإلقاح والحمل', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac692ccd-95d7-58d2-9f64-2428321331b3', '089e735c-146a-5920-ace4-7460262de9b7', 'ممَّ يُحسب اليوم الأوّل للدورة الجنسية عند المرأة؟', '[{"id":"a","text":"من يوم الإباضة"},{"id":"b","text":"من اليوم الأوّل للطمث"},{"id":"c","text":"من يوم الإلقاح"},{"id":"d","text":"من نهاية الطمث"}]'::jsonb, 'b', 'يُحسب اليوم الأوّل للدورة من اليوم الأوّل لنزول الطمث، وهو علامة واضحة وثابتة. الإباضة تقع في منتصف الدورة لا في بدايتها، والإلقاح حدث غير ثابت قد لا يحدث، ونهاية الطمث ليست المرجع المعتمد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c67cb32e-7846-59a3-b2c2-c0e3f3c415a0', '089e735c-146a-5920-ace4-7460262de9b7', 'ماذا يحدث لبطانة الرحم إذا لم يحدث إلقاح؟', '[{"id":"a","text":"تزداد سُمكًا باستمرار"},{"id":"b","text":"تتفكّك وتنزل مع الدم (الطمث)"},{"id":"c","text":"تتحوّل إلى بويضة"},{"id":"d","text":"تبقى ثابتة دون أيّ تغيير"}]'::jsonb, 'b', 'تتكاثف البطانة استعدادًا لاستقبال بيضة مخصّبة؛ فإن لم يحدث إلقاح تتفكّك وتنزل مع الدم وهذا هو الطمث. فهي لا تزداد سُمكًا بلا حدّ، ولا تتحوّل إلى بويضة (البويضة ينتجها المبيض)، ولا تبقى ثابتة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27d58d3d-e716-5945-ba4b-e2318bb17b86', '089e735c-146a-5920-ace4-7460262de9b7', 'أين تندمج النطفة بالبويضة (مكان الإلقاح)؟', '[{"id":"a","text":"في الرحم"},{"id":"b","text":"في المهبل"},{"id":"c","text":"في البوق (قناة فالوب)"},{"id":"d","text":"في المبيض"}]'::jsonb, 'c', 'يحدث الإلقاح عادةً في البوق، حيث تصعد النطاف وتلتقي بالبويضة بعد الإباضة. الرحم مكان التعشيش والنموّ، والمهبل قناة الجماع، والمبيض يطلق البويضة فقط ولا يحدث فيه الإلقاح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c75a4895-0130-5339-995b-fed589ccc2e7', '089e735c-146a-5920-ace4-7460262de9b7', 'ما الذي ينتج مباشرةً عن اندماج النطفة والبويضة؟', '[{"id":"a","text":"جنين مكتمل"},{"id":"b","text":"بيضة مخصّبة (لاقحة)"},{"id":"c","text":"نطفة جديدة"},{"id":"d","text":"بويضة جديدة"}]'::jsonb, 'b', 'ينتج عن اندماج المشيجين مباشرةً البيضة المخصّبة (اللاقحة)، وهي أوّل خليّة للكائن الجديد. الجنين مرحلة لاحقة تنشأ بعد انقسامات البيضة وتعشيشها، والاندماج لا ينتج مشيجًا جديدًا (نطفة أو بويضة).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1858eba0-43b3-541a-a62b-277d01ce38ad', '089e735c-146a-5920-ace4-7460262de9b7', 'لماذا ينقطع الطمث عند المرأة الحامل؟', '[{"id":"a","text":"لأنّ المبيض يتوقّف نهائيًّا عن العمل"},{"id":"b","text":"لأنّ البيضة المخصّبة انغرست فبقيت بطانة الرحم لاحتضان الجنين"},{"id":"c","text":"لأنّ الرحم يفرز دمًا أكثر"},{"id":"d","text":"لأنّ الإباضة تتكرّر كلّ يوم"}]'::jsonb, 'b', 'عند حدوث إلقاح وتعشيش، تبقى بطانة الرحم المتكاثفة لاحتضان الجنين بدل أن تتساقط، فينقطع الطمث؛ ولهذا يكون انقطاعه من أوّل علامات الحمل. وليس السبب توقّف المبيض نهائيًّا، ولا زيادة الدم، ولا تكرار الإباضة يوميًّا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdac01b9-568d-5517-b581-f8f07a8d378e', '089e735c-146a-5920-ace4-7460262de9b7', 'بِمَ يتمّ تبادل الغذاء والأكسجين بين الأمّ وجنينها أثناء الحمل؟', '[{"id":"a","text":"عن طريق المهبل"},{"id":"b","text":"عن طريق المشيمة والحبل السرّي"},{"id":"c","text":"عن طريق المبيضين"},{"id":"d","text":"عن طريق فم الجنين مباشرةً"}]'::jsonb, 'b', 'يتغذّى الجنين ويتنفّس عبر المشيمة والحبل السرّي اللذين يصلانه بدم الأمّ دون اختلاط الدمين. المهبل قناة الولادة لا التبادل، والمبيضان لا دور لهما في تغذية الجنين، والجنين لا يأكل ولا يتنفّس بفمه داخل الرحم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', '⚔️ زعيم الفصل: من البلوغ إلى الولادة', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a18cf58-a729-5b6b-86ae-5cb09623a3a7', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'ما الذي يفسّر ظهور العلامات الجنسية الثانوية عند البلوغ؟', '[{"id":"a","text":"إفراز الغدد التناسلية للهرمونات الجنسية"},{"id":"b","text":"نزول الطمث فقط"},{"id":"c","text":"اتّحاد النطفة بالبويضة"},{"id":"d","text":"نقص التغذية في الطفولة"}]'::jsonb, 'a', 'تظهر العلامات الثانوية (الصوت، الشعر، الثديان…) بفعل الهرمونات الجنسية التي تفرزها الغدد التناسلية عند نضجها (التستوستيرون عند الفتى، الإستروجين عند الفتاة). الطمث نتيجة من نتائج البلوغ عند الفتاة لا سبب لكلّ العلامات، واتّحاد المشيجين هو الإلقاح، والتغذية ليست العامل المتحكّم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69a02aa9-90e4-5e4d-8d70-0f3fd18602d5', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'في دورة منتظمة طولها 28 يومًا، أيّ فترة هي الأكثر احتمالًا لحدوث حمل عند الجماع؟', '[{"id":"a","text":"أثناء أيّام الطمث"},{"id":"b","text":"حول منتصف الدورة قرب الإباضة"},{"id":"c","text":"في اليوم الأخير من الدورة"},{"id":"d","text":"لا يحدث الحمل أبدًا قبل اليوم 25"}]'::jsonb, 'b', 'يحدث الحمل عندما تُلقَّح بويضةٌ متاحة؛ والإباضة تقع حول اليوم 14، فتكون الفترة المحيطة بها الأكثر خصوبة. أثناء الطمث لا توجد بويضة جديدة محرّرة بعد، وفي آخر الدورة تكون البويضة قد زالت إن لم تُلقّح، والقول إنّ الحمل مستحيل قبل اليوم 25 خاطئ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bb113d8-06cc-58d0-8aab-ccff595ec640', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'لماذا يحمل كلّ مشيج (نطفة أو بويضة) نصف المعلومة الوراثية فقط؟', '[{"id":"a","text":"حتّى يكون أصغر حجمًا"},{"id":"b","text":"كي يكتمل العدد عند اندماجهما فيرث الكائن الجديد من الأبوين معًا"},{"id":"c","text":"لأنّ المشيج خليّة ميتة"},{"id":"d","text":"لأنّ نصف المعلومة يضيع أثناء الإلقاح"}]'::jsonb, 'b', 'يحمل كلّ مشيج نصف الصبغيات؛ فعند اندماج النطفة بالبويضة يكتمل العدد في البيضة المخصّبة، فيرث الكائن الجديد المعلومة الوراثية من الأب والأمّ معًا. السبب ليس مجرّد الحجم، والمشيج خليّة حيّة، ولا تضيع المعلومة بل تجتمع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6052de6d-0e0c-5540-8c69-0b8b7ae3559d', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'بعد الإلقاح في البوق، ما التسلسل الصحيح للأحداث؟', '[{"id":"a","text":"تعشيش في الرحم ← انقسام البيضة ← إباضة"},{"id":"b","text":"انقسام البيضة المخصّبة وتنقّلها ← تعشيش في بطانة الرحم ← بداية الحمل"},{"id":"c","text":"نزول طمث ← إلقاح ثانٍ ← ولادة"},{"id":"d","text":"خروج البيضة عبر المهبل ← تعشيش في المبيض"}]'::jsonb, 'b', 'بعد الإلقاح تبدأ البيضة المخصّبة بالانقسام وهي تتنقّل من البوق نحو الرحم، ثمّ تنغرس (تتعشّش) في بطانة الرحم فيبدأ الحمل. الترتيب في باقي الخيارات خاطئ: الإباضة تسبق الإلقاح، والطمث ينقطع عند الحمل، والتعشيش يحدث في الرحم لا في المبيض.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31248994-d4f9-5171-bec2-d64dc992c83e', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'ما الدور الأساسي للسائل المنوي الذي تفرزه الغدد الملحقة؟', '[{"id":"a","text":"إنتاج النطاف"},{"id":"b","text":"تغذية النطاف وحملها لتنتقل وتبقى حيّة"},{"id":"c","text":"إنتاج البويضات"},{"id":"d","text":"تكوين بطانة الرحم"}]'::jsonb, 'b', 'السائل المنوي تفرزه الغدد الملحقة (الحُويصلتان المنويتان والبروستاتا) ليغذّي النطاف ويحملها فتبقى حيّة وتتمكّن من الحركة. النطاف نفسها تنتجها الخصية لا الغدد الملحقة، والبويضات ينتجها المبيض، وبطانة الرحم شأن أنثويّ لا علاقة له بالسائل المنوي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2ad13f4-0044-50d5-81a3-5c68b357afa6', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'علامَ يدلّ انقطاع الطمث المفاجئ عند امرأة في سنّ الإنجاب كانت دورتها منتظمة؟', '[{"id":"a","text":"على حدوث حمل محتمل (انغراس بيضة مخصّبة)"},{"id":"b","text":"على حدوث إباضة مزدوجة"},{"id":"c","text":"على أنّ المبيضين بدآ بإنتاج النطاف"},{"id":"d","text":"على أنّ بطانة الرحم تساقطت مرّتين"}]'::jsonb, 'a', 'انقطاع الطمث المفاجئ يدلّ على احتمال حمل، لأنّ تعشيش بيضة مخصّبة يُبقي بطانة الرحم فلا تتساقط. الإباضة المزدوجة لا توقف الطمث بحدّ ذاتها، والمبيضان لا ينتجان النطاف أبدًا (هذا دور الخصية)، وتساقط البطانة مرّتين هو عكس انقطاع الطمث.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', '👑 تحدّي النخبة: التكاثر والصحة الإنجابية — تحليل ومفاهيم', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2757d84a-6bee-5f43-a43e-c1300c8d0186', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'امرأة دورتها منتظمة طولها 30 يومًا. عُلِم أنّ الإباضة تحدث قبل بداية الدورة الموالية بنحو 14 يومًا. في أيّ يوم من الدورة تحدث الإباضة تقريبًا؟', '[{"id":"a","text":"اليوم 14"},{"id":"b","text":"اليوم 16"},{"id":"c","text":"اليوم 30"},{"id":"d","text":"اليوم 7"}]'::jsonb, 'b', 'الفترة بين الإباضة وبداية الطمث الموالي ثابتة نحو 14 يومًا، فتُحسب الإباضة بطرح 14 من طول الدورة: 30 − 14 = 16. فتقع في اليوم 16 لا اليوم 14 (الذي يصحّ في دورة 28 يومًا فقط). الخياران 30 و7 لا يطابقان هذه القاعدة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2368e5cc-5dc0-5694-b58e-b254eff67d81', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'أُجري تحليل لزوجين لم يُرزقا بأطفال، فتبيّن أنّ منيّ الرجل خالٍ تمامًا من النطاف بينما تبويض المرأة وأجهزتها سليمة. ما التفسير الأرجح لتعذّر حدوث الإلقاح؟', '[{"id":"a","text":"غياب المشيج الذكري يمنع اندماجه مع البويضة"},{"id":"b","text":"بطانة الرحم رقيقة جدًّا"},{"id":"c","text":"البويضة كبيرة الحجم"},{"id":"d","text":"المهبل قصير"}]'::jsonb, 'a', 'الإلقاح يستلزم اندماج مشيجين؛ فإذا خلا المنيّ من النطاف انعدم المشيج الذكري فاستحال الاندماج رغم سلامة جهة المرأة. أمّا سُمك البطانة فيؤثّر في التعشيش لا في غياب الإلقاح هنا، وكِبَر حجم البويضة أمر طبيعيّ، وطول المهبل لا يمنع صعود النطاف لو وُجدت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('523df43f-964d-58fd-96b5-9a5ce3b65b6b', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'لماذا تُغلَق البويضة أمام بقيّة النطاف فور دخول نطفة واحدة؟', '[{"id":"a","text":"لتسريع نزول الطمث"},{"id":"b","text":"لضمان اندماج نطفة واحدة فقط فيكتمل العدد الصبغي بشكل سليم"},{"id":"c","text":"لأنّ النطاف الأخرى أكبر حجمًا من البويضة"},{"id":"d","text":"لمنع تكوّن المشيمة"}]'::jsonb, 'b', 'الإغلاق يمنع دخول أكثر من نطفة، فيندمج مشيج ذكري واحد مع البويضة ويكتمل العدد الصبغي للكائن الجديد بشكل سليم؛ دخول عدّة نطاف يفسد هذا العدد. لا علاقة للأمر بتسريع الطمث (الذي ينقطع أصلًا عند الحمل)، ولا بأحجام النطاف، ولا بمنع المشيمة التي تتكوّن لاحقًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2b2b1e7-24ab-5e93-8e7d-caa36a43e82f', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'ادّعى تلميذ أنّ مصافحة زميل مصاب بالسيدا أو مشاركته مقعد الدراسة قد تنقل العدوى. ما الردّ العلمي الصحيح؟', '[{"id":"a","text":"الادّعاء صحيح، فالفيروس ينتقل بأيّ تلامس"},{"id":"b","text":"خاطئ؛ لا ينتقل الفيروس بالمصافحة أو المشاركة العادية، بل بالجنس غير المحمي والدم الملوّث ومن الأمّ إلى جنينها"},{"id":"c","text":"صحيح، لأنّ الفيروس ينتقل بالهواء"},{"id":"d","text":"صحيح، لأنّ لسعة البعوض تنقله"}]'::jsonb, 'b', 'فيروس السيدا (VIH) ينتقل عبر العلاقة الجنسية غير المحمية والدم الملوّث ومن الأمّ إلى جنينها، ولا ينتقل بالمصافحة أو المشاركة العادية أو الهواء أو البعوض. الادّعاء خاطئ ويؤدّي إلى وصم المصابين ظلمًا، والتوعية العلمية تصحّح هذه المفاهيم الخاطئة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae3e86ae-32dc-5c51-a4e2-977616c6f8a2', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'لماذا يُعدّ الواقي الذكري وسيلة وقاية مزدوجة في الصحة الإنجابية؟', '[{"id":"a","text":"لأنّه يعالج السيدا بعد الإصابة"},{"id":"b","text":"لأنّه يقي من الأمراض المنقولة جنسيًّا ويمنع الحمل غير المرغوب فيه معًا"},{"id":"c","text":"لأنّه يزيد إنتاج النطاف"},{"id":"d","text":"لأنّه يوقف الدورة الجنسية عند المرأة"}]'::jsonb, 'b', 'الواقي الذكري حاجز يمنع تبادل السوائل، فيقي في آنٍ واحد من العدوى بالأمراض المنقولة جنسيًّا (ومنها السيدا) ومن الحمل غير المرغوب فيه. وهو ليس علاجًا للسيدا، ولا يزيد إنتاج النطاف، ولا يوقف الدورة الجنسية للمرأة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34e03026-5e9d-54e3-8fcf-62aa589b5472', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'يُتابَع طفلٌ لأمّ مصابة بفيروس السيدا. أيّ تدبير يقلّل خطر انتقال الفيروس إليه؟', '[{"id":"a","text":"تجنّب مصافحة الأمّ لطفلها"},{"id":"b","text":"المتابعة الطبّية أثناء الحمل والولادة والحذر في الرضاعة وفق إرشاد الطبيب"},{"id":"c","text":"إبعاد الطفل عن الطعام المشترك"},{"id":"d","text":"منع الطفل من اللعب مع غيره"}]'::jsonb, 'b', 'ينتقل الفيروس من الأمّ إلى طفلها أثناء الحمل أو الولادة أو الرضاعة، لذا تقلّل المتابعة الطبّية في هذه المراحل من الخطر. المصافحة والطعام المشترك واللعب لا تنقل الفيروس أصلًا، فالتدابير المبنية عليها لا قيمة وقائية لها بل تسبّب وصمًا لا مبرّر له.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a274e462-368e-5cd0-8155-351efa152309', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed3b59f8-da5a-5bc4-a945-b8e1ef4a53b2', 'a274e462-368e-5cd0-8155-351efa152309', 'ما هو «المستضدّ» (الأنتيجان)؟', '[{"id":"a","text":"كرية بيضاء تبتلع الميكروبات"},{"id":"b","text":"جزيء غريب عن الجسم يستثير ردّ فعل دفاعيًّا"},{"id":"c","text":"جسم مضادّ ينتجه الجسم لمقاومة المرض"},{"id":"d","text":"دواء يقتل البكتيريا"}]'::jsonb, 'b', 'المستضدّ هو كلّ جزيء غريب (غير ذاتي) يدخل الجسم فيتعرّف عليه جهاز المناعة كأجنبيّ ويستثير الدفاع. الكرية البيضاء والجسم المضادّ أدوات دفاع لا مستضدّات، والدواء ليس جزءًا من جهاز المناعة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f9d4a7b-d61f-55a8-993f-2b53a5bacc9b', 'a274e462-368e-5cd0-8155-351efa152309', 'أيّ ممّا يلي حاجز طبيعي يمثّل خطّ الدفاع الأوّل؟', '[{"id":"a","text":"الأجسام المضادّة"},{"id":"b","text":"اللمفاويات T"},{"id":"c","text":"الجلد السليم"},{"id":"d","text":"البلعمة"}]'::jsonb, 'c', 'خطّ الدفاع الأوّل هو الحواجز الطبيعية مثل الجلد السليم والمخاطيّات والإفرازات. أمّا البلعمة فهي خطّ ثانٍ (مناعة غير نوعية)، والأجسام المضادّة واللمفاويات T من المناعة النوعية (خطّ ثالث).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6a2ae8b-8970-5fc6-9381-c86b66f46598', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الذي تنتجه اللمفاويات B؟', '[{"id":"a","text":"المضادّات الحيوية"},{"id":"b","text":"المخاط واللعاب"},{"id":"c","text":"الأجسام المضادّة"},{"id":"d","text":"الفيروسات"}]'::jsonb, 'c', 'اللمفاويات B تنتج الأجسام المضادّة، وهي بروتينات نوعية ذائبة في الدم ترتبط بالمستضدّ فتُبطل مفعوله. المضادّات الحيوية أدوية تُصنَّع خارج الجسم، والمخاط واللعاب إفرازات حواجز، والفيروسات ميكروبات ممرضة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4e554d8-cc06-5b4d-a4d4-e852123e2c7a', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الترتيب الصحيح لمراحل البلعمة؟', '[{"id":"a","text":"هضم ← ابتلاع ← التصاق ← إطراح"},{"id":"b","text":"التصاق ← ابتلاع ← هضم ← إطراح"},{"id":"c","text":"ابتلاع ← التصاق ← إطراح ← هضم"},{"id":"d","text":"إطراح ← هضم ← ابتلاع ← التصاق"}]'::jsonb, 'b', 'تبدأ البلعمة بالتصاق الكرية البيضاء بالميكروب، ثمّ ابتلاعه (الإحاطة به وإدخاله)، ثمّ هضمه بالإنزيمات، وأخيرًا إطراح البقايا. الترتيب المنطقي يبدأ بالاقتراب لا بالهضم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('225f6708-eb96-5ee3-89e9-35d42975fc0d', 'a274e462-368e-5cd0-8155-351efa152309', 'لماذا توصف البلعمة بأنّها مناعة «غير نوعية»؟', '[{"id":"a","text":"لأنّها تهاجم ميكروبًا واحدًا محدّدًا فقط"},{"id":"b","text":"لأنّها تتدخّل ضدّ أيّ غازٍ مهما كان نوعه"},{"id":"c","text":"لأنّها تنتج أجسامًا مضادّة نوعية"},{"id":"d","text":"لأنّها تحتفظ بذاكرة عن كلّ ميكروب"}]'::jsonb, 'b', 'البلعمة غير نوعية لأنّها تتدخّل بالطريقة نفسها ضدّ أيّ ميكروب دون تمييز نوعه ودون ذاكرة. التعرّف على ميكروب محدّد وإنتاج أجسام مضادّة نوعية وامتلاك الذاكرة كلّها خصائص المناعة النوعية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7bdf433-23d1-597d-9230-aa4c7eb71a0c', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الذي يميّز الجسم المضادّ بأنّه «نوعي»؟', '[{"id":"a","text":"أنّه يهاجم جميع الميكروبات في الجسم دفعةً واحدة"},{"id":"b","text":"أنّه يرتبط بمستضدّ واحد موافق له فقط كالمفتاح وقفله"},{"id":"c","text":"أنّه يبتلع الميكروب ويهضمه"},{"id":"d","text":"أنّه يدمّر اللمفاويات المصابة"}]'::jsonb, 'b', 'نوعية الجسم المضادّ تعني أنّه يتعرّف على مستضدّ واحد فقط يوافق شكله (كالمفتاح وقفله) ويرتبط به. لا يهاجم كلّ الميكروبات، والابتلاع والهضم وظيفة الكريات البلعمية، وتدمير الخلايا المصابة وظيفة اللمفاويات T.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c80316fd-ccd8-5796-8ce4-01ab290692ed', 'a274e462-368e-5cd0-8155-351efa152309', 'ما سبب خطورة السيدا (SIDA) على جهاز المناعة؟', '[{"id":"a","text":"أنّ فيروس VIH يقوّي اللمفاويات فيصبح الجسم مفرط المناعة"},{"id":"b","text":"أنّ فيروس VIH يدمّر اللمفاويات T فينهار جهاز المناعة وتظهر أمراض انتهازية"},{"id":"c","text":"أنّه بكتيريا تُعالَج بسهولة بالمضادّات الحيوية"},{"id":"d","text":"أنّه يزيد إنتاج الأجسام المضادّة بشكل مفرط"}]'::jsonb, 'b', 'فيروس VIH يهاجم ويدمّر اللمفاويات T الأساسية في المناعة النوعية، فينهار جهاز المناعة تدريجيًّا ويعجز الجسم عن مقاومة العدوى فتظهر أمراض انتهازية. السيدا فيروس لا بكتيريا، ولا تنفع معه المضادّات الحيوية، وهو يُضعف المناعة لا يقوّيها.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96d100ae-a565-548c-a68a-12d239d5149a', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الفرق الأساسي بين التلقيح والمصل؟', '[{"id":"a","text":"التلقيح يحقن أجسامًا مضادّة جاهزة، والمصل يحقن ميكروبًا مُضعَّفًا"},{"id":"b","text":"التلقيح يحقن ميكروبًا مُضعَّفًا فيصنع الجسمُ مناعته (وقاية)، والمصل يحقن أجسامًا مضادّة جاهزة (علاج سريع)"},{"id":"c","text":"كلاهما يحقن أجسامًا مضادّة جاهزة وتأثيرهما طويل الأمد"},{"id":"d","text":"التلقيح علاج فوري، والمصل وقاية طويلة الأمد"}]'::jsonb, 'b', 'التلقيح يُدخل ميكروبًا مُضعَّفًا أو ميّتًا فيستثير الجسم ليصنع أجسامه المضادّة وذاكرته المناعية: وقاية مسبقة طويلة الأمد. المصل يُدخل أجسامًا مضادّة جاهزة من غيره: علاج سريع لكن قصير الأمد ودون ذاكرة. الخياران (أ) و(د) يعكسان الدورين.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', 'تمرين: الميكروبات والحواجز الطبيعية', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d8bf231-f6cd-5321-b685-2e2237923776', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'أيّ ممّا يلي متعضّية مجهرية لا تتكاثر إلّا داخل خلية مضيفة؟', '[{"id":"a","text":"البكتيريا"},{"id":"b","text":"الفيروس"},{"id":"c","text":"الكرية البيضاء"},{"id":"d","text":"الجسم المضادّ"}]'::jsonb, 'b', 'الفيروس ليس خلية ولا يملك جهازًا للتكاثر بنفسه، فلا يتكاثر إلّا بدخول خلية حيّة (مضيفة) واستغلالها لصنع نسخ منه. أمّا البكتيريا فهي خلية تتكاثر بالانقسام بمفردها. الكرية البيضاء والجسم المضادّ من أدوات الدفاع لا من الميكروبات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfa1b322-f81a-506d-9a27-1e1469a2522c', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'بِمَ تُعالَج العدوى البكتيرية؟', '[{"id":"a","text":"بالمضادّات الحيوية"},{"id":"b","text":"باللقاحات فقط"},{"id":"c","text":"بمضادّات لا تؤثّر إلّا في الفيروسات"},{"id":"d","text":"لا علاج لها إطلاقًا"}]'::jsonb, 'a', 'المضادّات الحيوية (Antibiotiques) فعّالة ضدّ البكتيريا فتقتلها أو توقف تكاثرها. وهي لا تؤثّر في الفيروسات إطلاقًا. اللقاح وسيلة وقاية مسبقة لا علاج لعدوى قائمة، والعدوى البكتيرية قابلة للعلاج.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95219141-5521-5154-bb14-e1878ea1967d', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'ما المقصود بـ«العدوى»؟', '[{"id":"a","text":"إنتاج الجسم لأجسام مضادّة"},{"id":"b","text":"دخول متعضّية ممرضة إلى الجسم وتكاثرها فيه"},{"id":"c","text":"ابتلاع الكرية البيضاء للميكروب"},{"id":"d","text":"حقن مصل مضادّ للمرض"}]'::jsonb, 'b', 'العدوى هي دخول متعضّية مجهرية ممرضة إلى الجسم وتكاثرها فيه، عبر الهواء أو الماء أو الغذاء أو الجروح أو الاتّصال. إنتاج الأجسام المضادّة والبلعمة هما ردّا فعل دفاعيّان ضدّ العدوى لا العدوى ذاتها، وحقن المصل إجراء طبّي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ceffa55-c541-5898-a4c1-b4db8702b762', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'أيّ ممّا يلي ليس حاجزًا طبيعيًّا للدفاع عن الجسم؟', '[{"id":"a","text":"الجلد"},{"id":"b","text":"المخاط"},{"id":"c","text":"اللعاب والدموع"},{"id":"d","text":"الأجسام المضادّة"}]'::jsonb, 'd', 'الجلد والمخاط واللعاب والدموع حواجز طبيعية تمثّل خطّ الدفاع الأوّل الذي يمنع دخول الجراثيم. أمّا الأجسام المضادّة فتنتمي إلى المناعة النوعية (دفاع داخلي متأخّر) ولا تُعدّ حاجزًا طبيعيًّا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('905ca97e-bdc1-540b-94db-34981c0e26c4', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'لماذا لا تنفع المضادّات الحيوية في علاج الأنفلونزا؟', '[{"id":"a","text":"لأنّ الأنفلونزا تسبّبها بكتيريا قويّة جدًّا"},{"id":"b","text":"لأنّ الأنفلونزا يسبّبها فيروس، والمضادّ الحيوي فعّال ضدّ البكتيريا فقط"},{"id":"c","text":"لأنّ المضادّ الحيوي يقوّي الفيروس"},{"id":"d","text":"لأنّ الأنفلونزا ليست عدوى"}]'::jsonb, 'b', 'الأنفلونزا مرض فيروسي، والمضادّات الحيوية لا تؤثّر إلّا في البكتيريا لأنّها تستهدف بنى خلوية لا توجد في الفيروسات. فهي إذن عديمة الفائدة ضدّ الفيروسات ولا تقوّيها، والأنفلونزا عدوى فيروسية فعلًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3dd4d1bd-fb69-501c-845d-e29cb6378bb8', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'ما الذي يحدث عادةً عند جرح الجلد بأداة ملوّثة؟', '[{"id":"a","text":"يصبح الجسم محصّنًا نهائيًّا ضدّ كلّ الأمراض"},{"id":"b","text":"يُخترَق خطّ الدفاع الأوّل فتتمكّن الجراثيم من الدخول وقد تسبّب عدوى"},{"id":"c","text":"تتوقّف كلّ دفاعات الجسم"},{"id":"d","text":"تتحوّل الجراثيم تلقائيًّا إلى أجسام مضادّة"}]'::jsonb, 'b', 'الجلد السليم حاجز يمنع دخول الجراثيم؛ فإذا جُرح اختُرق خطّ الدفاع الأوّل وأمكن للجراثيم الدخول وإحداث عدوى، فتتدخّل عندها الكريات البيضاء (خطّ ثانٍ). الجرح لا يمنح مناعة دائمة ولا يوقف الدفاعات، والجراثيم لا تتحوّل إلى أجسام مضادّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('796f9185-d6da-58cb-a816-baa7f2ac578d', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', 'تمرين: البلعمة والمناعة النوعية', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc1b9db7-ba16-5a86-a122-88533ff7851f', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'ما الخلايا المسؤولة عن البلعمة؟', '[{"id":"a","text":"الكريات الحمراء"},{"id":"b","text":"الكريات البيضاء البلعمية"},{"id":"c","text":"الصفيحات الدموية"},{"id":"d","text":"خلايا الجلد"}]'::jsonb, 'b', 'البلعمة تقوم بها الكريات البيضاء البلعمية التي تبتلع الميكروب وتهضمه. الكريات الحمراء تنقل الأكسجين، والصفيحات تتدخّل في تخثّر الدم، وخلايا الجلد حاجز طبيعي لا خلايا بلعمية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eec7086d-db3e-5470-9329-1f506b013b6a', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'ما هي المرحلة الأخيرة في عملية البلعمة؟', '[{"id":"a","text":"الالتصاق"},{"id":"b","text":"الابتلاع"},{"id":"c","text":"إطراح بقايا الميكروب المهضوم"},{"id":"d","text":"الهضم"}]'::jsonb, 'c', 'تنتهي البلعمة بإطراح بقايا الميكروب بعد هضمه. الترتيب: التصاق ثمّ ابتلاع ثمّ هضم ثمّ إطراح، فالإطراح هو الخطوة الأخيرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc91df15-6b43-5536-891e-95745aadbbde', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'علامات الاحمرار والتورّم والألم والحرارة موضعيًّا تدلّ على:', '[{"id":"a","text":"شفاء تامّ ونهائي"},{"id":"b","text":"الالتهاب الذي يرافق نشاط الكريات البيضاء"},{"id":"c","text":"توقّف جهاز المناعة"},{"id":"d","text":"إنتاج مصل داخل الجسم"}]'::jsonb, 'b', 'هذه العلامات الأربع تميّز الالتهاب، وهو ردّ فعل دفاعي يرافق توافد الكريات البيضاء إلى مكان العدوى ونشاطها. وهو دليل على عمل المناعة لا على توقّفها، وليس شفاءً تامًّا، والجسم لا ينتج «مصلًا».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('491b4317-0ecd-5415-a65d-7748002fc11d', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'أيّ نوع من اللمفاويات يهاجم مباشرةً الخلايا المصابة ويدمّرها؟', '[{"id":"a","text":"اللمفاويات B"},{"id":"b","text":"اللمفاويات T"},{"id":"c","text":"الكريات الحمراء"},{"id":"d","text":"الصفيحات الدموية"}]'::jsonb, 'b', 'اللمفاويات T مسؤولة عن المناعة الخلوية: تتعرّف على الخلايا المصابة (المعدِية) وتدمّرها مباشرةً. أمّا اللمفاويات B فتنتج أجسامًا مضادّة (مناعة خلطية)، والكريات الحمراء والصفيحات ليست لمفاويات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b92226a3-6d6f-56b2-bc2f-4e4d93714d2b', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'لماذا لا يمرض الشخص غالبًا عند لقائه ميكروبًا سبق له أن واجهه؟', '[{"id":"a","text":"لأنّ الميكروب يضعف من تلقاء نفسه مع الزمن"},{"id":"b","text":"بفضل الذاكرة المناعية التي تجعل الردّ الثاني أسرع وأقوى"},{"id":"c","text":"لأنّ الجلد يصبح أكثر سُمكًا"},{"id":"d","text":"لأنّ المضادّات الحيوية تبقى دائمًا في الدم"}]'::jsonb, 'b', 'بعد أوّل لقاء يحتفظ الجسم بخلايا ذاكرة، فعند لقاء ثانٍ بالميكروب نفسه يكون الردّ المناعي أسرع وأقوى فيُقضى عليه قبل ظهور المرض. الميكروب لا يضعف ذاتيًّا، والجلد لا يتغيّر سُمكه لذلك، والمضادّات الحيوية أدوية لا تبقى في الدم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba12d467-f325-53d7-b435-6e2016012912', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'تُسمّى مناعة اللمفاويات B التي تعتمد على أجسام مضادّة ذائبة في سوائل الجسم:', '[{"id":"a","text":"مناعة خلوية"},{"id":"b","text":"مناعة خلطية"},{"id":"c","text":"مناعة غير نوعية"},{"id":"d","text":"مناعة وراثية"}]'::jsonb, 'b', 'تُسمّى مناعة خلطية لأنّها محمولة في أخلاط الجسم (سوائله كالدم) عبر الأجسام المضادّة التي تنتجها اللمفاويات B. أمّا المناعة الخلوية فتقوم بها اللمفاويات T مباشرةً، والبلعمة غير نوعية، ولا توجد «مناعة وراثية» بهذا المعنى هنا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', '⚔️ زعيم الفصل: التلقيح والمصل واضطراب المناعة', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14e823cf-30fc-548c-8963-37b1b24a36a7', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'في التلقيح، من الذي ينتج الأجسام المضادّة؟', '[{"id":"a","text":"تُحقن جاهزة من جسم آخر"},{"id":"b","text":"ينتجها جسم الملقَّح نفسه استجابةً للميكروب المُضعَّف"},{"id":"c","text":"تنتجها البكتيريا داخل اللقاح"},{"id":"d","text":"لا تُنتج أجسام مضادّة في التلقيح"}]'::jsonb, 'b', 'اللقاح يحتوي ميكروبًا مُضعَّفًا أو ميّتًا (أو مستضدّه) يستثير جسم الملقَّح ليصنع أجسامه المضادّة وخلايا ذاكرته. حقن أجسام مضادّة جاهزة من جسم آخر هو المصل لا التلقيح، والبكتيريا لا تنتج أجسامًا مضادّة، والتلقيح يستهدف أصلًا إنتاجها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa75f8a4-9f9d-5f88-b206-083dc4bad1fc', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'ماذا تعني عبارة «السيدا متلازمة العوز المناعي المكتسب»؟', '[{"id":"a","text":"أنّه مرض وراثي ينتقل من الأبوين فقط"},{"id":"b","text":"أنّه حالة نقص في مناعة الجسم مكتسبة بسبب فيروس VIH"},{"id":"c","text":"أنّه فرط في نشاط المناعة"},{"id":"d","text":"أنّه عدوى بكتيرية بسيطة"}]'::jsonb, 'b', '«العوز المناعي» = نقص المناعة، و«المكتسب» = ناتج عن عدوى (فيروس VIH) لا عن وراثة. فهو إذن ضعف في المناعة لا فرط فيها، وليس وراثيًّا ولا عدوى بكتيرية بسيطة، بل عدوى فيروسية خطيرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('547b29ab-ebe8-58f9-a489-6a9762f2bb63', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'أيّ من هذه الطرق لا ينتقل بها فيروس السيدا (VIH)؟', '[{"id":"a","text":"الدم الملوّث ومشاركة أدوات الحقن"},{"id":"b","text":"من الأمّ المصابة إلى جنينها"},{"id":"c","text":"المصافحة ومشاركة الطعام والعطس"},{"id":"d","text":"العلاقة الجنسية غير المحميّة"}]'::jsonb, 'c', 'ينتقل VIH عبر الدم الملوّث وأدوات الحقن المشتركة، والعلاقة الجنسية غير المحميّة، ومن الأمّ إلى جنينها. أمّا المصافحة ومشاركة الطعام والعطس فلا تنقله، ولذلك لا مبرّر لإقصاء المصابين اجتماعيًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6079308-2039-5fd4-8588-4b70638d9877', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'مريض أُصيب بجرح ملوّث ويُخشى عليه من الكزاز، فما الإجراء العلاجي العاجل المناسب؟', '[{"id":"a","text":"حقن لقاح فقط والانتظار أسابيع"},{"id":"b","text":"حقن مصل مضادّ للكزاز لأنّه يوفّر أجسامًا مضادّة جاهزة فوريّة"},{"id":"c","text":"إعطاؤه مضادًّا حيويًّا فقط دون أيّ إجراء مناعي"},{"id":"d","text":"عدم التدخّل لأنّ الجسم سيتكفّل وحده فورًا"}]'::jsonb, 'b', 'الحالة طارئة تتطلّب حماية فورية، والمصل يمنح أجسامًا مضادّة جاهزة تعمل حالًا فيناسب العلاج العاجل. اللقاح بطيء (يحتاج أيّامًا لبناء المناعة) فلا يكفي وحده في الطوارئ، والاكتفاء بالامتناع أو بالمضادّ الحيوي لا يبطل سُمّ الكزاز بسرعة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf81a271-35e2-51bd-a56f-7a22097ffc11', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'أيّ العبارات التالية صحيحة بخصوص مدّة الحماية؟', '[{"id":"a","text":"التلقيح يمنح حماية قصيرة، والمصل حماية طويلة الأمد"},{"id":"b","text":"التلقيح يمنح حماية طويلة الأمد (بذاكرة مناعية)، والمصل حماية قصيرة (بلا ذاكرة)"},{"id":"c","text":"كلاهما يمنح حماية دائمة مدى الحياة"},{"id":"d","text":"كلاهما حماية قصيرة لا تتجاوز اليوم"}]'::jsonb, 'b', 'التلقيح يُكسب الجسم ذاكرة مناعية فتكون حمايته طويلة الأمد، بينما المصل يقدّم أجسامًا مضادّة جاهزة تُستهلك ولا تترك ذاكرة فحمايته قصيرة. لذلك لا يصحّ القول إنّهما متساويان في المدّة ولا أنّ المصل أطول من التلقيح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85975a29-3b73-5283-b45c-50082f7bbdef', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'لماذا يصبح مريض السيدا عرضةً لأمراض كثيرة قد تكون قاتلة؟', '[{"id":"a","text":"لأنّ الفيروس يقوّي اللمفاويات فيهاجم الجسمُ نفسَه"},{"id":"b","text":"لأنّ تدمير اللمفاويات T يُضعف المناعة النوعية فيعجز الجسم عن مقاومة العدوى"},{"id":"c","text":"لأنّ الجلد يفقد كلّ حواجزه الطبيعية فجأةً"},{"id":"d","text":"لأنّ الجسم ينتج فائضًا من الأجسام المضادّة"}]'::jsonb, 'b', 'VIH يدمّر اللمفاويات T الأساسية في المناعة النوعية، فينهار الدفاع تدريجيًّا ويعجز الجسم عن مقاومة الميكروبات فتظهر أمراض انتهازية قد تكون قاتلة. الفيروس يُضعف المناعة لا يقوّيها، والمشكلة في اللمفاويات لا في الجلد، ولا علاقة لها بفائض الأجسام المضادّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', '👑 تحدّي النخبة: المناعة — تحليل وتركيب', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8aacf3aa-1540-535d-aeeb-1f5a6d3b1fad', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'بعد حقن لقاح، قِيس تركيز الأجسام المضادّة في الدم: ارتفع ارتفاعًا ضعيفًا وبطيئًا بعد الحقنة الأولى، ثمّ ارتفع ارتفاعًا قويًّا وسريعًا بعد الحقنة الثانية بالمستضدّ نفسه. ما التفسير الصحيح؟', '[{"id":"a","text":"الحقنة الثانية أدخلت أجسامًا مضادّة جاهزة"},{"id":"b","text":"الردّ الثاني أقوى وأسرع بفضل الذاكرة المناعية المتكوّنة بعد الحقنة الأولى"},{"id":"c","text":"الجسم نسي المستضدّ تمامًا بين الحقنتين"},{"id":"d","text":"المستضدّ تكاثر داخل الدم فأنتج الأجسام المضادّة بنفسه"}]'::jsonb, 'b', 'الحقنة الأولى تُكوّن خلايا ذاكرة، فعند اللقاء الثاني بالمستضدّ نفسه يكون الردّ أسرع وأقوى (إنتاج وفير وسريع للأجسام المضادّة). اللقاح لا يحقن أجسامًا مضادّة جاهزة (ذلك دور المصل)، والذاكرة تنفي النسيان، والمستضدّ لا ينتج الأجسام المضادّة بل يستثير الجسم لإنتاجها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e59e6651-39d8-51cc-b0ab-77d608c80ba9', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'قورن بين تجربتين: فأر (أ) حُقن بميكروب مُضعَّف ثمّ بعد أسابيع بالميكروب الممرض فلم يمرض؛ فأر (ب) حُقن مباشرةً بالميكروب الممرض فمرض. ما الاستنتاج؟', '[{"id":"a","text":"الميكروب المُضعَّف هو الذي قتل الميكروب الممرض في دم الفأر (أ)"},{"id":"b","text":"الحقن الأوّل بالميكروب المُضعَّف أكسب الفأر (أ) مناعة (تلقيح) فقاوم الميكروب الممرض"},{"id":"c","text":"الفأر (ب) كان أضعف بنية فقط دون علاقة بالمناعة"},{"id":"d","text":"الميكروب الممرض غير ممرض أصلًا"}]'::jsonb, 'b', 'الفرق الوحيد بين الفأرين هو الحقن المسبق بالميكروب المُضعَّف؛ فبما أنّ الفأر (أ) لم يمرض، فإنّ هذا الحقن أكسبه مناعة (مبدأ التلقيح: ذاكرة وأجسام مضادّة). لا يبقى الميكروب المُضعَّف ليقتل الممرض، والفأر (ب) مرض لأنّه غير ملقَّح، والميكروب ممرض فعلًا بدليل مرض (ب).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90feb615-2b2b-56ba-943e-5d42595f4154', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'طفلٌ تعرّض لعضّة كلب يُشتبه بإصابته بالكَلَب (داء السُّعار). لِمَ يُعطى عادةً المصل واللقاح معًا؟', '[{"id":"a","text":"المصل يمنح حماية فورية بأجسام مضادّة جاهزة، واللقاح يبني حماية طويلة الأمد لاحقًا"},{"id":"b","text":"لأنّ المصل واللقاح شيء واحد لا فرق بينهما"},{"id":"c","text":"لأنّ كليهما يحقن ميكروبًا مُضعَّفًا"},{"id":"d","text":"لأنّ اللقاح يعمل فورًا والمصل بعد أسابيع"}]'::jsonb, 'a', 'الكَلَب خطير ويحتاج حمايةً فورية يوفّرها المصل (أجسام مضادّة جاهزة تعمل حالًا)، يرافقه اللقاح ليبني مناعة طويلة الأمد عبر الذاكرة. هما مختلفان (المصل أجسام جاهزة، اللقاح ميكروب مُضعَّف)، والفوري هو المصل لا اللقاح، فالخياران الباقيان يقلبان الأدوار.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7f9403b-2a71-5bf8-8bc8-8bcda864c2ce', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'لوحظ في دم مريض بالسيدا انخفاضٌ متواصل في عدد اللمفاويات T مع تزايد العدوى الانتهازية. ما العلاقة السببية الصحيحة؟', '[{"id":"a","text":"العدوى الانتهازية هي التي تخلق فيروس VIH"},{"id":"b","text":"تدمير VIH للمفاويات T يُضعف المناعة، فتنتهز الميكروبات هذا الضعف وتسبّب العدوى"},{"id":"c","text":"انخفاض اللمفاويات T يقوّي المناعة فتقلّ العدوى"},{"id":"d","text":"لا علاقة بين اللمفاويات T والعدوى الانتهازية"}]'::jsonb, 'b', 'VIH يدمّر اللمفاويات T فينخفض عددها وتضعف المناعة النوعية، فتنتهز الميكروبات هذا الضعف وتسبّب أمراضًا (عدوى انتهازية). العلاقة طردية بين هبوط اللمفاويات وتزايد العدوى. العدوى لا تخلق الفيروس، وهبوط اللمفاويات يُضعف المناعة لا يقوّيها، والعلاقة قائمة لا منعدمة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9be8486-4590-5088-9040-3192630fe12a', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'مريضٌ يعاني عدوى فيروسية، فطلب من الطبيب مضادًّا حيويًّا «ليشفى أسرع». ما الردّ العلمي الصحيح؟', '[{"id":"a","text":"المضادّ الحيوي سيقضي على الفيروس فورًا"},{"id":"b","text":"المضادّ الحيوي لا يؤثّر في الفيروسات، وسوء استعماله قد يسبّب مقاومة البكتيريا للمضادّات"},{"id":"c","text":"المضادّ الحيوي يقوّي الفيروس فيشتدّ المرض دائمًا"},{"id":"d","text":"المضادّ الحيوي يتحوّل داخل الجسم إلى لقاح ضدّ الفيروس"}]'::jsonb, 'b', 'المضادّات الحيوية تستهدف البكتيريا فقط ولا أثر لها في الفيروسات، فطلبها لعدوى فيروسية لا فائدة منه، بل استعمالها العشوائي يسهم في نشوء بكتيريا مقاومة للمضادّات. وهو لا يقتل الفيروس ولا «يقوّيه» ولا يتحوّل إلى لقاح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e9d7a5c-3647-547e-adee-13a69d9dbf1c', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'صُنّف التالي ترتيبًا منطقيًّا لخطوط الدفاع عند دخول ميكروب اخترق الجلد: (1) الأجسام المضادّة النوعية، (2) الحواجز الطبيعية، (3) البلعمة. ما الترتيب الزمني الصحيح لتدخّلها؟', '[{"id":"a","text":"1 ثمّ 2 ثمّ 3"},{"id":"b","text":"2 ثمّ 3 ثمّ 1"},{"id":"c","text":"3 ثمّ 1 ثمّ 2"},{"id":"d","text":"1 ثمّ 3 ثمّ 2"}]'::jsonb, 'b', 'الدفاع يبدأ بالحواجز الطبيعية (خطّ أوّل يمنع الدخول)، فإذا اخترقها الميكروب تدخّلت البلعمة (مناعة غير نوعية سريعة)، وإن لم تكفِ تدخّلت المناعة النوعية بالأجسام المضادّة واللمفاويات (أبطأ وأدقّ). إذن: 2 ثمّ 3 ثمّ 1، وبقيّة الترتيبات تخالف هذا التسلسل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d832856d-91f0-58a4-80d5-4f60a4473575', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35a00c12-9909-5c2a-8a00-be13c99fc7b7', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'أين توجد الصبغيّات (الكروموزومات) داخل الخليّة؟', '[{"id":"a","text":"في الغشاء الخلوي"},{"id":"b","text":"في النواة"},{"id":"c","text":"في السيتوبلازم خارج النواة"},{"id":"d","text":"في جدار الخليّة"}]'::jsonb, 'b', 'الصبغيّات هي الحوامل المادّية للبرنامج الوراثي وتوجد داخل **نواة** الخليّة. أمّا الغشاء والسيتوبلازم والجدار فلا تحمل الصبغيّات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7aec043-f953-5f1a-9ec0-7af39cb26cc9', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'كم صبغيًّا تحتوي خلايا جسم الإنسان؟', '[{"id":"a","text":"23 صبغيًّا"},{"id":"b","text":"24 صبغيًّا"},{"id":"c","text":"46 صبغيًّا"},{"id":"d","text":"92 صبغيًّا"}]'::jsonb, 'c', 'خلايا الجسم تحتوي على **46 صبغيًّا أي 23 زوجًا**. والعدد 23 هو عدد صبغيّات المشيج (نصف العدد) وليس عدد صبغيّات خلايا الجسم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b1bcb5a-a641-5b43-8dbc-3d3c02c5b70a', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما الزوج الصبغيّ الجنسي عند الذكر وعند الأنثى عند الإنسان؟', '[{"id":"a","text":"الذكر XX والأنثى XY"},{"id":"b","text":"الذكر XY والأنثى XX"},{"id":"c","text":"الذكر YY والأنثى XX"},{"id":"d","text":"الذكر والأنثى كلاهما XY"}]'::jsonb, 'b', 'الأنثى تحمل **XX** والذكر يحمل **XY**. لا يوجد فرد بزوج YY لأنّ كلّ فرد يرث صبغيّ X واحدًا على الأقلّ من أمّه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4bae8e5-dfff-5896-8a67-3de4e2a159db', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما الفرق بين الصبغيّ والمورّثة (الجين)؟', '[{"id":"a","text":"المورّثة أكبر من الصبغيّ وتحتوي عليه"},{"id":"b","text":"الصبغيّ والمورّثة شيء واحد بأسماء مختلفة"},{"id":"c","text":"الصبغيّ مقطع صغير داخل المورّثة"},{"id":"d","text":"المورّثة مقطع من الـ ADN محمول على الصبغيّ ومسؤول عن صفة"}]'::jsonb, 'd', 'المورّثة (الجين) هي **مقطع من الـ ADN** محمول على الصبغيّ ومسؤول عن صفة وراثية واحدة. الصبغيّ أكبر بكثير ويحمل آلاف المورّثات، فهما ليسا الشيء نفسه، والصبغيّ لا يقع داخل المورّثة بل العكس.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27d2d9fb-50f4-5a3b-832a-a9ff231e850c', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ممّ يتكوّن الصبغيّ أساسًا؟', '[{"id":"a","text":"من جزيء الـ ADN الحامل للمورّثات"},{"id":"b","text":"من الماء فقط"},{"id":"c","text":"من الأمشاج"},{"id":"d","text":"من خلايا صغيرة متراصّة"}]'::jsonb, 'a', 'يتكوّن كلّ صبغيّ من جزيء **الـ ADN** الذي يحمل على طوله المورّثات. الأمشاج خلايا تناسلية وليست مكوّنًا للصبغيّ، والصبغيّ ليس مجموعة خلايا بل جزء من خليّة واحدة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86618ab4-ad97-58d2-8e24-7ac78edb4f33', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'من الذي يحدّد جنس المولود ولماذا؟', '[{"id":"a","text":"الأمّ، لأنّ البويضة تحمل أحيانًا X وأحيانًا Y"},{"id":"b","text":"الأب، لأنّ النطفة تحمل إمّا X وإمّا Y بينما البويضة تحمل X دائمًا"},{"id":"c","text":"الأمّ، لأنّها تحمل XX"},{"id":"d","text":"يتحدّد الجنس صدفةً بعد الولادة"}]'::jsonb, 'b', 'البويضة تحمل **X دائمًا**، أمّا النطفة فتحمل إمّا X (فينتج XX = أنثى) وإمّا Y (فينتج XY = ذكر). إذن **الأب** هو الذي يحدّد الجنس وليس الأمّ، ويتحدّد لحظة الإلقاح لا بعد الولادة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d6632dd-7eec-56fd-acc3-0209ae0a41bb', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'إذا كان الحليل A سائدًا و a متنحّيًا، أيّ تركيب تظهر فيه الصفة المتنحّية؟', '[{"id":"a","text":"A//A"},{"id":"b","text":"A//a"},{"id":"c","text":"a//a"},{"id":"d","text":"كلّ التركيبات السابقة"}]'::jsonb, 'c', 'لا تظهر الصفة المتنحّية إلّا حين يجتمع حليلان متنحّيان **a//a**. أمّا A//A و A//a فتظهر فيهما الصفة السائدة لأنّ A يطغى على a؛ والمهجّن A//a يبدو سائدًا لكنّه يحمل a وينقله.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f80763c6-ffd4-5598-b20c-406692d2ce77', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما سبب متلازمة داون (التثلّث الصبغي 21)؟', '[{"id":"a","text":"نقص صبغيّ فيصبح العدد 45"},{"id":"b","text":"وجود ثلاث نسخ من الصبغيّ رقم 21 فيصبح العدد 47"},{"id":"c","text":"غياب الصبغيّات الجنسية"},{"id":"d","text":"صفة مكتسبة من المحيط"}]'::jsonb, 'b', 'في متلازمة داون توجد **ثلاث نسخ من الصبغيّ 21** بدل نسختين، فيصبح المجموع **47 صبغيًّا** بدل 46. فهي ناتجة عن خلل في **عدد الصبغيّات**، وليست نقصًا ولا صفة مكتسبة من المحيط.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('87a68336-6ce3-5711-a664-f4b1b9a9bd05', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', 'تمرين: الصبغيّات والنمط النووي', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
