  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56da94ad-3837-52f8-81b8-74647738a219', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'أيّ ممّا يلي يُعدّ صفة وراثية؟', '[{"id":"a","text":"إتقان السباحة"},{"id":"b","text":"لون العينين"},{"id":"c","text":"ندبة في الذراع"},{"id":"d","text":"تعلّم لغة أجنبية"}]'::jsonb, 'b', 'الصفة الوراثية تُورَّث عبر الأمشاج مثل **لون العينين**. أمّا السباحة وتعلّم اللغة فهي مهارات مكتسبة، والندبة أثر يكتسبه الجسم من المحيط؛ والصفات المكتسبة لا تنتقل إلى الأبناء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('773ce225-2606-5cbc-974d-b21426cabd50', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'كم زوجًا من الصبغيّات توجد في خلايا جسم الإنسان؟', '[{"id":"a","text":"23 زوجًا"},{"id":"b","text":"46 زوجًا"},{"id":"c","text":"22 زوجًا"},{"id":"d","text":"11 زوجًا"}]'::jsonb, 'a', 'خلايا الجسم تحتوي على 46 صبغيًّا مرتّبة في **23 زوجًا**. العدد 46 هو عدد الصبغيّات لا الأزواج، و22 هو عدد أزواج الصبغيّات الجسمية فقط (دون الزوج الجنسي).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('137d9695-303a-550a-92f8-4100be9b598d', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'ماذا نسمّي الصورة المرتّبة لصبغيّات خليّة حسب حجمها وشكلها في أزواج؟', '[{"id":"a","text":"المورّثة"},{"id":"b","text":"النمط النووي (caryotype)"},{"id":"c","text":"المشيج"},{"id":"d","text":"البيضة المخصّبة"}]'::jsonb, 'b', '**النمط النووي (caryotype)** هو ترتيب صبغيّات الخليّة في أزواج حسب الحجم والشكل، ويُستعمل لكشف أيّ خلل في عدد الصبغيّات. أمّا المورّثة فجزء من الـ ADN، والمشيج والبيضة المخصّبة خلايا لا صور.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85f28f4b-b0ae-5abc-bd27-14fc560e394f', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'في كلّ زوج من الصبغيّات المتماثلة عند الإنسان:', '[{"id":"a","text":"الصبغيّان كلاهما من الأمّ"},{"id":"b","text":"الصبغيّان كلاهما من الأب"},{"id":"c","text":"صبغيّ من الأب وصبغيّ من الأمّ"},{"id":"d","text":"صبغيّ واحد فقط دون أصل محدّد"}]'::jsonb, 'c', 'في كلّ زوج صبغيّ متماثل **صبغيّ موروث من الأب وآخر من الأمّ**، ولذلك يرث الابن صفاته من الأبوين معًا. فلا يأتي الزوجان من والد واحد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('360e1e1c-e34d-522e-b88d-60a6544c87dd', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'أيّ ترتيب صحيح من الأكبر إلى الأصغر؟', '[{"id":"a","text":"المورّثة ← الصبغيّ ← النواة"},{"id":"b","text":"النواة ← الصبغيّ ← المورّثة"},{"id":"c","text":"الصبغيّ ← النواة ← المورّثة"},{"id":"d","text":"الـ ADN ← النواة ← الصبغيّ"}]'::jsonb, 'b', 'ترتيب الاحتواء الصحيح: **النواة ← الصبغيّ ← الـ ADN ← المورّثة**. فالنواة تحوي الصبغيّات، وكلّ صبغيّ يتكوّن من ADN يحمل المورّثات. إذن النواة أكبر، والمورّثة أصغر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d2d3287-9e19-5a41-bd76-9d109ae06236', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'خليّة جسمية فيها 47 صبغيًّا بسبب ثلاث نسخ من الصبغيّ 21؛ هذا يدلّ على:', '[{"id":"a","text":"نمط نووي عادي لإنسان سليم"},{"id":"b","text":"متلازمة داون (التثلّث الصبغي 21)"},{"id":"c","text":"أنّها خليّة مشيج"},{"id":"d","text":"صفة مكتسبة من المحيط"}]'::jsonb, 'b', 'وجود **47 صبغيًّا** بسبب ثلاث نسخ من الصبغيّ 21 هو سمة **متلازمة داون**. النمط العادي 46 صبغيًّا، والمشيج فيه 23 فقط، والخلل في عدد الصبغيّات سبب وراثي لا صفة مكتسبة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4fa23279-6976-5b3e-9a66-2b31fc791adc', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', 'تمرين: المورّثات والـ ADN وتحديد الجنس', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
