INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71f7f295-09e6-5967-b8bc-a4fbe6e6d491', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'ماذا نسمّي الجزيء الطويل الذي يتكوّن منه الصبغيّ ويحمل المورّثات؟', '[{"id":"a","text":"المشيج"},{"id":"b","text":"الـ ADN"},{"id":"c","text":"النواة"},{"id":"d","text":"الحليل"}]'::jsonb, 'b', 'يتكوّن الصبغيّ من جزيء **الـ ADN** الذي يحمل على طوله المورّثات. النواة بنية تحوي الصبغيّات لا جزيء، والمشيج خليّة تناسلية، والحليل شكل من أشكال المورّثة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdbbd4f3-efdc-5f8d-b062-5920e2748b11', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'ما المورّثة (الجين)؟', '[{"id":"a","text":"نواة الخليّة كاملة"},{"id":"b","text":"مقطع من الـ ADN مسؤول عن صفة وراثية"},{"id":"c","text":"زوج كامل من الصبغيّات"},{"id":"d","text":"خليّة تناسلية"}]'::jsonb, 'b', 'المورّثة **مقطع من الـ ADN** يحدّد صفة وراثية واحدة. فهي ليست النواة ولا زوجًا كاملًا من الصبغيّات (الصبغيّ يحمل آلاف المورّثات)، وليست خليّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86c1b473-6c80-5ae9-b67c-587df9e21a29', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'كم صبغيًّا يحمل المشيج (النطفة أو البويضة) عند الإنسان؟', '[{"id":"a","text":"46 صبغيًّا"},{"id":"b","text":"23 صبغيًّا"},{"id":"c","text":"47 صبغيًّا"},{"id":"d","text":"92 صبغيًّا"}]'::jsonb, 'b', 'يحمل المشيج **23 صبغيًّا** أي نصف عدد صبغيّات خلايا الجسم، حتّى إذا اتّحد مشيجان عند الإلقاح تكوّنت بيضة مخصّبة فيها 46 صبغيًّا من جديد. العدد 46 خاصّ بخلايا الجسم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ad0af0b-064e-5c4f-a536-c12c4b51b674', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'أيّ نوع من الصبغيّات تحمله البويضة دائمًا؟', '[{"id":"a","text":"X دائمًا"},{"id":"b","text":"Y دائمًا"},{"id":"c","text":"X أو Y بالتساوي"},{"id":"d","text":"لا تحمل صبغيًّا جنسيًّا"}]'::jsonb, 'a', 'بما أنّ الأمّ XX، فكلّ بويضة تحمل صبغيّ **X**. النطفة هي التي تحمل X أو Y بالتساوي، أمّا البويضة فلا يمكن أن تحمل Y لأنّ الأمّ لا تملكه أصلًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92784226-bd9f-5e72-bfd7-85d74478961f', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'نطفة تحمل صبغيّ Y أخصبت بويضة؛ ما جنس المولود وزوجه الجنسي؟', '[{"id":"a","text":"أنثى XX"},{"id":"b","text":"ذكر XY"},{"id":"c","text":"ذكر XX"},{"id":"d","text":"أنثى XY"}]'::jsonb, 'b', 'البويضة تحمل X والنطفة تحمل Y، فيتكوّن الزوج **XY = ذكر**. لو حملت النطفة X لكان المولود أنثى XX. فالنطفة (الأب) هي التي تحدّد الجنس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a780469f-de41-55c6-921c-4ace85279c6d', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'في كلّ حمل، ما احتمال أن يكون المولود ذكرًا؟', '[{"id":"a","text":"25 ٪"},{"id":"b","text":"50 ٪"},{"id":"c","text":"75 ٪"},{"id":"d","text":"100 ٪"}]'::jsonb, 'b', 'تحمل النطف نوعين بالتساوي (X و Y)، فاحتمال XY (ذكر) = احتمال XX (أنثى) = **50 ٪** في كلّ حمل. والاحتمال مستقلّ عن جنس المواليد السابقين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a5d10140-e10e-53fe-844c-e63b967a6636', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', '👹 زعيم الفصل: السائد والمتنحّي وانتقال الصفات', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
