INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f4880f3-8cdb-5b90-a220-963449cf81cc', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'إذا كان A (لون أسود) سائدًا و a (لون بنّي) متنحّيًا، أيّ تركيب يُظهر اللون البنّي؟', '[{"id":"a","text":"A//A"},{"id":"b","text":"A//a"},{"id":"c","text":"a//a"},{"id":"d","text":"A//A و A//a معًا"}]'::jsonb, 'c', 'اللون البنّي صفة متنحّية لا تظهر إلّا بـ **a//a**. التركيبان A//A و A//a يُظهران اللون الأسود السائد لأنّ A يطغى على a.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3c255f0-011f-5efe-9041-ee2a43d71b28', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'فرد مظهره يطابق الصفة السائدة لكنّه ينقل الصفة المتنحّية لأبنائه؛ ما تركيبه الوراثي؟', '[{"id":"a","text":"A//A نقيّ سائد"},{"id":"b","text":"A//a مهجّن"},{"id":"c","text":"a//a نقيّ متنحٍّ"},{"id":"d","text":"لا يمكن أن يحدث ذلك"}]'::jsonb, 'b', 'الفرد **المهجّن A//a** يُظهر الصفة السائدة (بفضل A) لكنّه يحمل الحليل المتنحّي a وينقله إلى أبنائه. النقيّ A//A لا يحمل a إطلاقًا، والنقيّ a//a تظهر عليه الصفة المتنحّية لا السائدة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('75e75676-0c66-5d10-af00-98f6ad0aeb25', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'لماذا يُعدّ الـ ADN «حاملًا للبرنامج الوراثي»؟', '[{"id":"a","text":"لأنّه يحمل المورّثات التي تحدّد الصفات وتُنسخ عند تكوين الخلايا"},{"id":"b","text":"لأنّه يوجد خارج النواة"},{"id":"c","text":"لأنّه صفة مكتسبة"},{"id":"d","text":"لأنّه يتغيّر تبعًا للمحيط فقط"}]'::jsonb, 'a', 'يحمل الـ ADN على طوله **المورّثات** التي تحدّد الصفات الوراثية، وتنتقل نسخة منه عند تكوين الأمشاج فينقل البرنامج إلى الجيل التالي. وهو يوجد داخل النواة لا خارجها، وليس صفة مكتسبة من المحيط.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bacef7f6-427b-5d36-bb58-893321bddf0e', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'تزاوج بين فردين نقيّين: A//A (سائد) × a//a (متنحٍّ). ما تركيب كلّ الأبناء في الجيل الأوّل ومظهرهم؟', '[{"id":"a","text":"كلّهم a//a وتظهر عليهم الصفة المتنحّية"},{"id":"b","text":"كلّهم A//a وتظهر عليهم الصفة السائدة"},{"id":"c","text":"نصفهم A//A ونصفهم a//a"},{"id":"d","text":"كلّهم A//A وتظهر عليهم الصفة السائدة"}]'::jsonb, 'b', 'كلّ والد نقيّ ينتج مشيجًا من نوع واحد: الأوّل A والثاني a. فيتّحدان فيكون كلّ الأبناء **A//a مهجّنين**، وتظهر عليهم **الصفة السائدة** لأنّ A يطغى على a.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a773a17b-68c4-52e0-8679-ae7eb08b021c', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'أبوان سليمان أنجبا طفلًا مصابًا بمرض وراثي متنحٍّ؛ ماذا نستنتج عن الأبوين؟', '[{"id":"a","text":"كلاهما مصاب بالمرض"},{"id":"b","text":"كلّ منهما حامل للحليل المتنحّي (مهجّن) دون أن يكون مريضًا"},{"id":"c","text":"أحدهما فقط يحمل المرض"},{"id":"d","text":"المرض مكتسب من المحيط"}]'::jsonb, 'b', 'بما أنّ المرض **متنحٍّ**، فإصابة الطفل تعني أنّه ورث الحليل المعطوب من **كلا الأبوين**. ولأنّ الأبوين سليمان فكلّ منهما **مهجّن حامل** (يحمل حليلًا متنحّيًا واحدًا) دون أن يمرض. لو حمل أحدهما فقط لما اجتمع الحليلان المتنحّيان عند الطفل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e8e482b-15ff-5865-9b5d-f0a9699f641a', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'نمط نووي لخليّة جسمية يُظهر 44 صبغيًّا جسميًّا + XY؛ ما المعطى الذي نستخلصه؟', '[{"id":"a","text":"أنثى عدد صبغيّاتها 46"},{"id":"b","text":"ذكر عدد صبغيّاته 46"},{"id":"c","text":"مصاب بمتلازمة داون"},{"id":"d","text":"مشيج عدد صبغيّاته 23"}]'::jsonb, 'b', '44 صبغيًّا جسميًّا (22 زوجًا) + الزوج الجنسي XY = **46 صبغيًّا**، والزوج XY يدلّ على **ذكر**. الأنثى تكون XX، ومتلازمة داون تُظهر 47 صبغيًّا، والمشيج يحمل 23 لا 46.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

