  ('1733d648-9849-51c2-8a74-f26b0ad28cea', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', '👑 تحدّي النخبة: مسائل وراثية مركّبة', 4, 300, 60, 'challenge', 'admin', 4)
