INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89a3a1e1-0845-5603-9a6e-00105be7b896', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'لماذا يستحيل أن يرث الابن صبغيّ Y من أمّه؟', '[{"id":"a","text":"لأنّ الأمّ XX ولا تملك صبغيّ Y أصلًا"},{"id":"b","text":"لأنّ البويضة تفقد Y أثناء الإلقاح"},{"id":"c","text":"لأنّ صبغيّ Y يأتي من المحيط"},{"id":"d","text":"لأنّ الأمّ تنقل صفاتها المكتسبة فقط"}]'::jsonb, 'a', 'الأمّ زوجها الجنسي **XX**، فهي لا تملك صبغيّ Y إطلاقًا، ولذلك لا يمكن أن تنقله. صبغيّ Y يأتي حصرًا من الأب (XY) عبر النطفة، وهو ما يجعل الأب محدّد الجنس.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90aeeea5-4c06-58ae-a3df-79e08c57a989', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'نملك حليلين: B (بنّي) سائد و b (أزرق) متنحٍّ للون العينين. أب أزرق العينين (b//b) وأمّ مهجّنة (B//b). ما النسبة المنتظرة للأبناء زرق العينين؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"100 ٪"}]'::jsonb, 'c', 'الأب b//b ينتج أمشاج b فقط. الأمّ B//b تنتج نصف أمشاجها B ونصفها b. التركيبات الممكنة: B//b (بنّي) بنسبة 50 ٪، و b//b (أزرق) بنسبة 50 ٪. إذن **50 ٪** من الأبناء زرق العينين (b//b).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b127b66-0b2d-5231-9c9c-e7c75dd13eda', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'أبوان بنّيا العينين أنجبا طفلًا أزرق العينين (الأزرق متنحٍّ b//b). ما تركيب كلٍّ من الأبوين؟', '[{"id":"a","text":"كلاهما B//B"},{"id":"b","text":"كلاهما B//b (مهجّنان)"},{"id":"c","text":"أحدهما B//B والآخر b//b"},{"id":"d","text":"كلاهما b//b"}]'::jsonb, 'b', 'الطفل أزرق العينين b//b ورث b من كلّ والد. وبما أنّ الأبوين بنّيا العينين (يحملان B الظاهر) فكلّ منهما **B//b مهجّن**: يحمل B فيبدو بنّيًّا، ويحمل b فينقله. لو كان أحدهما B//B لما أمكن أن يرث الطفل b منه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cc80dc1-af6b-571f-8fac-8bea7f168b76', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'في مرض وراثي متنحٍّ، أب مصاب (a//a) وأمّ سليمة حاملة (A//a). ما احتمال أن يكون الطفل مصابًا؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"75 ٪"}]'::jsonb, 'c', 'الأب a//a ينتج أمشاج a فقط. الأمّ A//a تنتج نصفها A ونصفها a. التركيبات: A//a (سليم حامل) 50 ٪، و a//a (مصاب) 50 ٪. إذن احتمال أن يكون الطفل **مصابًا = 50 ٪**.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f62f0da-43e1-59f6-8b58-cc16fd625e2a', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'خليّة جسمية لأنثى مصابة بمتلازمة داون؛ كم صبغيًّا جسميًّا (autosome) تحمل، وما زوجها الجنسي؟', '[{"id":"a","text":"44 صبغيًّا جسميًّا + XX، المجموع 46"},{"id":"b","text":"45 صبغيًّا جسميًّا + XX، المجموع 47"},{"id":"c","text":"44 صبغيًّا جسميًّا + XY، المجموع 46"},{"id":"d","text":"46 صبغيًّا جسميًّا + XX، المجموع 48"}]'::jsonb, 'b', 'التثلّث الصبغي 21 يضيف نسخة ثالثة إلى الصبغيّات **الجسمية** فيصبح عددها 45 بدل 44، أمّا الزوج الجنسي فيبقى **XX** (أنثى). المجموع = 45 + 2 = **47 صبغيًّا**. الخلل في الصبغيّات الجسمية لا الجنسية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d20073c4-39c9-54e5-85c5-0d0ca6394aff', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'تزاوج بين فردين مهجّنين A//a × A//a (A سائد، a متنحٍّ). ما النسبة المنتظرة للأبناء الذين تظهر عليهم الصفة المتنحّية؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"75 ٪"}]'::jsonb, 'b', 'كلّ والد مهجّن ينتج نصف أمشاجه A ونصفها a. التركيبات الممكنة: A//A، A//a، a//A، a//a بنسب متساوية (1:2:1). تظهر الصفة المتنحّية فقط في **a//a** أي ربع الحالات = **25 ٪**، بينما 75 ٪ تظهر عليهم الصفة السائدة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a20a238-a2b1-57fc-b649-829296191a8e', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما هو الزلزال؟', '[{"id":"a","text":"هزّة أرضية مفاجئة ناتجة عن تحرّر مفاجئ لطاقة في أعماق الأرض"},{"id":"b","text":"ارتفاع تدريجي بطيء لسطح الأرض على مدى سنوات"},{"id":"c","text":"تدفّق الحمم البركانية فوق سطح الأرض"},{"id":"d","text":"تيّار هوائي قويّ يحرّك الغبار قرب السطح"}]'::jsonb, 'a', 'الزلزال هزّة أرضية مفاجئة وعابرة سببها تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق، تنتقل على شكل موجات زلزالية. وهو غير ظواهر بطيئة كرفع السطح، وغير البراكين التي تخصّ تدفّق الحمم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f6bf23f-9526-5ada-ae7e-0dae2870a1fc', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما الفرق بين البؤرة والمركز السطحي؟', '[{"id":"a","text":"البؤرة على السطح، والمركز السطحي في العمق فوقها"},{"id":"b","text":"البؤرة نقطة المنشأ في العمق، والمركز السطحي النقطة على السطح فوقها مباشرة"},{"id":"c","text":"هما اسمان لنفس النقطة على سطح الأرض"},{"id":"d","text":"البؤرة أبعد منطقة عن الزلزال، والمركز السطحي أقربها"}]'::jsonb, 'b', 'البؤرة هي نقطة منشأ الزلزال داخل الأرض (في العمق) وتنطلق منها الموجات، أمّا المركز السطحي فهو النقطة الواقعة على سطح الأرض عموديًّا فوق البؤرة مباشرة، وهي الأكثر تضرّرًا. والخلط بينهما خطأ شائع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da45a278-22b0-5c97-8252-a4583ddafef4', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما اسم الجهاز الذي يكشف اهتزازات الأرض ويسجّلها؟', '[{"id":"a","text":"المرصاد الزلزالي (sismographe)"},{"id":"b","text":"مقياس الحرارة (thermomètre)"},{"id":"c","text":"مقياس الضغط الجوّي (baromètre)"},{"id":"d","text":"البوصلة"}]'::jsonb, 'a', 'المرصاد الزلزالي (sismographe) جهاز يكشف اهتزازات الأرض ويسجّلها في رسم يُسمّى المخطّط الزلزالي (sismogramme). أمّا مقياس الحرارة والضغط والبوصلة فتقيس ظواهر أخرى لا علاقة لها بالزلازل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65f1a1e6-58d6-59a4-8184-84ad6c26c3c1', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ من التدابير التالية يُعدّ وقاية صحيحة من أضرار الزلازل؟', '[{"id":"a","text":"بناء مقاوم للزلازل واحترام معايير البناء"},{"id":"b","text":"بناء المباني العالية فقط عند الفوالق النشطة"},{"id":"c","text":"إيقاف المرصاد الزلزالي لتوفير الطاقة"},{"id":"d","text":"الوقوف قرب النوافذ الزجاجية أثناء الهزّة"}]'::jsonb, 'a', 'لا يمكن منع الزلازل لكن يمكن التقليل من أضرارها بالبناء المقاوم للزلازل واحترام معايير البناء، وخرائط المخاطر، والتربية على السلامة، والإنذار المبكّر. أمّا البناء عند الفوالق النشطة أو الوقوف قرب النوافذ فيزيدان الخطر، وإيقاف المرصاد يحرمنا من المراقبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98a8b766-e594-564b-8a39-f32f8d51c296', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ نوع من الموجات الزلزالية يصل أوّلًا إلى المرصاد الزلزالي؟', '[{"id":"a","text":"الموجات السطحية"},{"id":"b","text":"الموجات الثانوية (S)"},{"id":"c","text":"الموجات الأوّلية (P)"},{"id":"d","text":"تصل كلّ الموجات في الوقت نفسه"}]'::jsonb, 'c', 'الموجات الأوّلية (P) هي الأسرع فتصل أوّلًا إلى المرصاد، تليها الموجات الثانوية (S) الأبطأ، ثمّ الموجات السطحية. ومن فرق زمن وصول P و S يُحدَّد موقع المركز السطحي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d3f0d1b-37f9-5375-8817-cefb99e387ca', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ سلّم يُستعمل لقياس مقدار الزلزال (الطاقة المحرَّرة)؟', '[{"id":"a","text":"سلّم ميركالّي"},{"id":"b","text":"سلّم سلسيوس"},{"id":"c","text":"سلّم ريشتر"},{"id":"d","text":"سلّم بوفور"}]'::jsonb, 'c', 'يُقاس مقدار الزلزال (الطاقة المحرَّرة عند البؤرة) بسلّم ريشتر انطلاقًا من تسجيلات المرصاد. أمّا سلّم ميركالّي فيقيس الشدّة (آثار الزلزال على السطح)، وسلسيوس للحرارة، وبوفور لقوّة الريح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b20b4cf-270a-5ce0-a311-d9517b887488', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما الفرق بين شدّة الزلزال ومقداره؟', '[{"id":"a","text":"الشدّة قيمة واحدة للزلزال، والمقدار يختلف من مكان لآخر"},{"id":"b","text":"الشدّة تقيس آثار الزلزال على السطح وتختلف من مكان لآخر، والمقدار يقيس الطاقة المحرَّرة وقيمته واحدة"},{"id":"c","text":"هما يقيسان الشيء نفسه بسلّمين مختلفين"},{"id":"d","text":"الشدّة تقاس بسلّم ريشتر والمقدار بسلّم ميركالّي"}]'::jsonb, 'b', 'الشدّة تقيس آثار الزلزال المُلاحَظة على السطح (أضرار، إحساس الناس) وتختلف من موضع لآخر (سلّم ميركالّي). أمّا المقدار فيقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة مهما تعدّدت أماكن القياس (سلّم ريشتر). والخلط بينهما خطأ شائع.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d859e196-71a8-50e6-ba77-f28d2884ea23', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما السبب الرئيسي لمعظم الزلازل؟', '[{"id":"a","text":"هطول الأمطار الغزيرة على سطح الأرض"},{"id":"b","text":"دوران الأرض حول الشمس"},{"id":"c","text":"حركة الصفائح التكتونية وانكسار الصخور على الفوالق عند حدودها"},{"id":"d","text":"ارتفاع درجة حرارة الجوّ في فصل الصيف"}]'::jsonb, 'c', 'تنشأ معظم الزلازل عن حركة الصفائح التكتونية: تتراكم الضغوط عند حدود الصفائح حتى تتجاوز مقاومة الصخور فتنكسر فجأة على مستوى فالق، فتتحرّر الطاقة دفعةً واحدة. لذلك تتركّز الزلازل عند حدود الصفائح. والأمطار والحرارة ودوران الأرض ليست أسبابًا للزلازل.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d88a2774-8652-59a1-bc01-b2d51cd56be3', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'تمرين: الزلزال والبؤرة والمركز السطحي', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('725ed275-3afa-5fbf-bf81-caf4b6fdbbcc', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'الزلزال ناتج أساسًا عن:', '[{"id":"a","text":"تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق"},{"id":"b","text":"تبخّر مياه البحار بسرعة كبيرة"},{"id":"c","text":"سقوط النيازك على سطح الأرض دائمًا"},{"id":"d","text":"ذوبان الجليد في القطبين"}]'::jsonb, 'a', 'الزلزال هزّة مفاجئة سببها تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق، تنتقل على شكل موجات زلزالية. أمّا تبخّر المياه وذوبان الجليد فظواهر سطحية لا تحرّر هذه الطاقة، وسقوط النيازك سبب نادر جدًّا وليس السبب الأساسي.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1a72a3c-bf11-5d5f-bf0d-54e2d869f279', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'البؤرة (le foyer) هي:', '[{"id":"a","text":"النقطة على سطح الأرض التي يحسّ فيها الناس بالهزّة"},{"id":"b","text":"النقطة داخل الأرض التي تنطلق منها الموجات الزلزالية"},{"id":"c","text":"الجهاز الذي يسجّل الزلزال"},{"id":"d","text":"سلّم لقياس قوّة الزلزال"}]'::jsonb, 'b', 'البؤرة هي نقطة منشأ الزلزال داخل الأرض (في العمق) وتنطلق منها الموجات الزلزالية. أمّا النقطة على السطح فهي المركز السطحي، والجهاز هو المرصاد الزلزالي، والسلّم يخصّ قياس المقدار أو الشدّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9f283ed-6a7c-5c8b-8d54-b3c204480640', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'المركز السطحي (l''épicentre) هو:', '[{"id":"a","text":"النقطة الأعمق في باطن الأرض"},{"id":"b","text":"أبعد منطقة عن الزلزال"},{"id":"c","text":"النقطة على سطح الأرض الواقعة عموديًّا فوق البؤرة مباشرة"},{"id":"d","text":"مركز الكرة الأرضية"}]'::jsonb, 'c', 'المركز السطحي هو النقطة على سطح الأرض الواقعة عموديًّا فوق البؤرة مباشرة، وهي عادةً الأكثر تضرّرًا لأنّها الأقرب إلى البؤرة. وهو ليس نقطة في العمق ولا مركز الأرض ولا أبعد منطقة عن الزلزال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3834eb4e-5a63-54c8-88f2-d78b3998b401', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'ما العلاقة الصحيحة بين الزلزال والموجات الزلزالية؟', '[{"id":"a","text":"الموجات الزلزالية هي سبب الزلزال"},{"id":"b","text":"الزلزال يحرّر طاقة تنتقل على شكل موجات زلزالية تُحدث الاهتزاز"},{"id":"c","text":"لا علاقة بين الزلزال والموجات الزلزالية"},{"id":"d","text":"الموجات الزلزالية تنتشر فقط في الغلاف الجوّي"}]'::jsonb, 'b', 'عند الزلزال تتحرّر طاقة عند البؤرة تنتقل على شكل موجات زلزالية تنتشر في الصخور وتُحدث اهتزاز السطح. فالموجات نتيجة لتحرّر الطاقة وليست سببًا للزلزال، وهي تنتشر في الأرض لا في الهواء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40428907-308f-5afa-9838-2d8b1b4781f1', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'أين تقع البؤرة بالنسبة للمركز السطحي؟', '[{"id":"a","text":"في العمق تحت المركز السطحي مباشرة"},{"id":"b","text":"على السطح بجانب المركز السطحي"},{"id":"c","text":"في الغلاف الجوّي فوق المركز السطحي"},{"id":"d","text":"البؤرة والمركز السطحي في نفس المكان تمامًا"}]'::jsonb, 'a', 'البؤرة تقع في العمق داخل الأرض، والمركز السطحي يقع على السطح عموديًّا فوقها مباشرة. فالبؤرة إذن تحت المركز السطحي مباشرة. وليست على السطح ولا في الجوّ، وليست في نفس مكان المركز السطحي لأنّ هذا في العمق وذاك على السطح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b714b909-99c3-50bd-8d4d-1c3c63c3e53b', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'لماذا تكون المنطقة قرب المركز السطحي عادةً الأكثر تضرّرًا؟', '[{"id":"a","text":"لأنّها أبعد المناطق عن البؤرة"},{"id":"b","text":"لأنّها الأقرب إلى البؤرة فتصلها الموجات أقوى"},{"id":"c","text":"لأنّ المرصاد الزلزالي موجود فيها دائمًا"},{"id":"d","text":"لأنّ الموجات تتوقّف عندها فجأة"}]'::jsonb, 'b', 'المركز السطحي هو الأقرب إلى البؤرة، فتصله الموجات الزلزالية وهي أقوى، لذلك يكون عادةً الأكثر تضرّرًا. وكلّما ابتعدنا عنه ضعفت آثار الزلزال تدريجيًّا. ووجود المرصاد لا علاقة له بالأضرار.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2f705317-1f56-54d3-a7e5-61d7945a6a56', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'تمرين: الموجات وتسجيلها والشدّة والمقدار', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77baee2e-263c-5970-8b40-c6bf998173a3', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'الموجات الأوّلية (P) تتميّز بأنّها:', '[{"id":"a","text":"الأبطأ وتصل أخيرًا"},{"id":"b","text":"الأسرع وتصل أوّلًا إلى المرصاد"},{"id":"c","text":"لا تنتشر إلّا في الهواء"},{"id":"d","text":"لا تُسجَّل في المرصاد الزلزالي"}]'::jsonb, 'b', 'الموجات الأوّلية (P) هي الأسرع، فتصل أوّلًا إلى المرصاد الزلزالي، تليها الموجات الثانوية (S) الأبطأ. وتنتشر الموجات في الصخور لا في الهواء، وتُسجَّل جميعها في المرصاد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d9445fb-6119-55b3-b6ad-ca0c619576f1', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'الرسم الذي يسجّله المرصاد الزلزالي للاهتزازات يُسمّى:', '[{"id":"a","text":"المخطّط الزلزالي (sismogramme)"},{"id":"b","text":"الخريطة الطبوغرافية"},{"id":"c","text":"سلّم ريشتر"},{"id":"d","text":"المخطّط الحراري"}]'::jsonb, 'a', 'المخطّط الزلزالي (sismogramme) هو الرسم الذي يسجّله المرصاد الزلزالي ويبيّن سعة الاهتزازات وزمن وصول الموجات. أمّا سلّم ريشتر فهو مقياس للمقدار، والخريطة الطبوغرافية والمخطّط الحراري ظواهر أخرى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d59298e9-7418-5d6b-81f9-b2892d20f5d5', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'كيف يحدّد العلماء موقع المركز السطحي للزلزال؟', '[{"id":"a","text":"من لون الصخور المحيطة بالبؤرة"},{"id":"b","text":"من فرق زمن وصول الموجات P و S المسجَّل في المراصد"},{"id":"c","text":"من درجة حرارة الجوّ وقت الزلزال"},{"id":"d","text":"من سرعة الرياح في المنطقة"}]'::jsonb, 'b', 'بما أنّ الموجات P أسرع من S، يكبر فرق زمن وصولهما كلّما ابتعد المرصاد عن المركز السطحي. وبجمع معطيات عدّة مراصد يمكن تحديد موقع المركز السطحي. ولا علاقة لذلك بلون الصخور أو حرارة الجوّ أو الرياح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ccf3dff4-c04d-501a-a013-05a7d2962b44', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'شدّة الزلزال (l''intensité):', '[{"id":"a","text":"تقيس الطاقة المحرَّرة عند البؤرة ولها قيمة واحدة"},{"id":"b","text":"تقيس آثار الزلزال على السطح وتختلف من مكان إلى آخر"},{"id":"c","text":"تُقاس بسلّم ريشتر فقط"},{"id":"d","text":"ثابتة في كلّ نقاط الأرض"}]'::jsonb, 'b', 'الشدّة تقيس آثار الزلزال المُلاحَظة على السطح (الأضرار، إحساس الناس) وتختلف من مكان إلى آخر للزلزال نفسه، وتُقاس بسلّم ميركالّي. أمّا قياس الطاقة المحرَّرة بقيمة واحدة فهو المقدار (بسلّم ريشتر).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8e1d932-6b1e-5677-a7fb-3f2585c44174', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'مقدار الزلزال (la magnitude):', '[{"id":"a","text":"يقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة للزلزال الواحد"},{"id":"b","text":"يقيس آثار الزلزال ويتغيّر من مدينة إلى أخرى"},{"id":"c","text":"يُقاس بسلّم ميركالّي الوصفي"},{"id":"d","text":"يدلّ على عدد المباني المنهارة فقط"}]'::jsonb, 'a', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة، وله قيمة واحدة للزلزال الواحد مهما تعدّدت أماكن القياس، ويُقاس بسلّم ريشتر. أمّا قياس الآثار المتغيّرة من مكان لآخر بسلّم ميركالّي فهو الشدّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c65975ff-f3fb-5c32-a5ee-efdc8c6f4518', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'زلزال واحد سُجّل في عدّة مدن. أيّ القياسين يبقى ثابتًا؟', '[{"id":"a","text":"الشدّة، لأنّها تقيس الآثار على السطح"},{"id":"b","text":"المقدار، لأنّه يقيس الطاقة المحرَّرة عند البؤرة"},{"id":"c","text":"كلاهما يتغيّر من مدينة إلى أخرى"},{"id":"d","text":"كلاهما ثابت لا يتغيّر أبدًا"}]'::jsonb, 'b', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة فيبقى ثابتًا (قيمة واحدة) مهما تعدّدت المدن. أمّا الشدّة فتقيس الآثار على السطح فتختلف من مدينة إلى أخرى حسب القرب من المركز السطحي ونوع التربة والبناء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7b43517f-f4b4-5927-9c82-970e9805f797', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'زعيم الفصل: أسباب الزلازل وحركة الصفائح', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b5453e8-a3cf-5de8-a7c1-226aafb06278', '7b43517f-f4b4-5927-9c82-970e9805f797', 'ما الذي يحدث في الصخور لحظة وقوع الزلزال التكتوني؟', '[{"id":"a","text":"تتمدّد الصخور ببطء دون انكسار"},{"id":"b","text":"تنكسر الصخور فجأة على مستوى فالق فتتحرّر الطاقة المخزّنة دفعةً واحدة"},{"id":"c","text":"تذوب الصخور وتتحوّل إلى حمم سطحية"},{"id":"d","text":"تتبخّر الصخور تمامًا"}]'::jsonb, 'b', 'تتراكم الضغوط في الصخور حتى تتجاوز مقاومتها، فتنكسر فجأة على مستوى فالق وتتحرّر الطاقة المخزّنة دفعةً واحدة على شكل موجات زلزالية. وهذا غير الذوبان (الذي يخصّ البراكين) وغير التمدّد البطيء أو التبخّر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35271850-977a-5554-bbe3-72d8437bfceb', '7b43517f-f4b4-5927-9c82-970e9805f797', 'أين تتركّز معظم الزلازل في العالم؟', '[{"id":"a","text":"في وسط الصفائح بعيدًا عن حدودها"},{"id":"b","text":"عند حدود الصفائح التكتونية"},{"id":"c","text":"في الصحارى الرملية فقط"},{"id":"d","text":"في المناطق القطبية المتجمّدة فقط"}]'::jsonb, 'b', 'تتركّز معظم الزلازل عند حدود الصفائح التكتونية حيث تحتكّ الصفائح وتتراكم الضغوط، ومنها حوض البحر الأبيض المتوسّط الذي تقع فيه تونس. أمّا وسط الصفائح والصحارى والقطبين فليست مناطق زلزالية مميّزة بحدّ ذاتها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3671e022-537d-558c-bc83-c5b6c887f596', '7b43517f-f4b4-5927-9c82-970e9805f797', 'ما الفالق (la faille)؟', '[{"id":"a","text":"جهاز لقياس الزلازل"},{"id":"b","text":"كسر في الصخور يحدث على طوله انزلاق مفاجئ يحرّر الطاقة"},{"id":"c","text":"موجة زلزالية سطحية"},{"id":"d","text":"سلّم لقياس مقدار الزلزال"}]'::jsonb, 'b', 'الفالق كسر في الصخور يحدث على طوله انزلاق مفاجئ حين تتجاوز الضغوط مقاومة الصخور، فتتحرّر الطاقة وينشأ الزلزال. وليس جهازًا (المرصاد) ولا موجة ولا سلّمًا (ريشتر/ميركالّي).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c86b888-acae-5405-803e-337f9656b635', '7b43517f-f4b4-5927-9c82-970e9805f797', 'لماذا تُعتبر تونس منطقة معرّضة للنشاط الزلزالي؟', '[{"id":"a","text":"لأنّها تقع وسط صفيحة بعيدة عن أيّ حدود"},{"id":"b","text":"لأنّها قريبة من منطقة التقاء الصفائح في حوض البحر الأبيض المتوسّط"},{"id":"c","text":"لأنّ مناخها حارّ وجافّ"},{"id":"d","text":"لأنّها تكثر فيها الأمطار"}]'::jsonb, 'b', 'تقع تونس قرب منطقة التقاء الصفائح في حوض البحر الأبيض المتوسّط حيث تتراكم الضغوط، لذلك تتعرّض لنشاط زلزالي. والمناخ والأمطار لا علاقة لهما بأسباب الزلازل التكتونية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d2c52cf-0c3c-5f30-8a94-70f58b61e9d9', '7b43517f-f4b4-5927-9c82-970e9805f797', 'أيّ تسلسل يصف نشأة الزلزال التكتوني بشكل صحيح؟', '[{"id":"a","text":"تساقط أمطار ← تشبّع التربة ← اهتزاز"},{"id":"b","text":"حركة الصفائح ← تراكم الضغوط ← انكسار الصخور على فالق ← تحرّر الطاقة وموجات زلزالية"},{"id":"c","text":"ارتفاع الحرارة ← تبخّر المياه ← هزّة"},{"id":"d","text":"هبوب رياح قويّة ← انزلاق الرمال ← زلزال"}]'::jsonb, 'b', 'التسلسل الصحيح: حركة الصفائح التكتونية تراكم الضغوط عند الحدود تجاوز مقاومة الصخور وانكسارها على فالق تحرّر مفاجئ للطاقة على شكل موجات زلزالية. أمّا الأمطار والحرارة والرياح فليست أسبابًا لهذا التسلسل التكتوني.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('161a8d73-1f98-5032-b759-c9f3020c4cd4', '7b43517f-f4b4-5927-9c82-970e9805f797', 'زلزالان لهما المقدار نفسه، لكن أحدهما سبّب أضرارًا أكبر بكثير. ما التفسير الأرجح؟', '[{"id":"a","text":"هذا مستحيل: المقدار نفسه يعني الأضرار نفسها دائمًا"},{"id":"b","text":"اختلاف الشدّة بسبب عمق البؤرة وقرب العمران ونوع التربة وجودة البناء"},{"id":"c","text":"اختلاف لون الصخور بين المنطقتين"},{"id":"d","text":"اختلاف فصل السنة فقط"}]'::jsonb, 'b', 'المقدار يقيس الطاقة عند البؤرة، لكن الأضرار (الشدّة) تتأثّر بعمق البؤرة، وقرب المركز السطحي من العمران، ونوع التربة، وجودة البناء. لذلك قد يسبّب زلزالان بنفس المقدار أضرارًا مختلفة. واللون والفصل لا يفسّران ذلك.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0e6d4948-f756-5b0e-a27a-05de124a5644', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'تحدّي النخبة: المخاطر والوقاية وتركيب المفاهيم', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('509e52da-1efa-54f9-9da1-4eeaa51f355c', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ما السلوك الصحيح أثناء حدوث زلزال داخل مبنى؟', '[{"id":"a","text":"الوقوف قرب النوافذ الزجاجية لمشاهدة الخارج"},{"id":"b","text":"الاحتماء تحت طاولة متينة والابتعاد عن النوافذ"},{"id":"c","text":"استعمال المصعد فورًا للنزول بسرعة"},{"id":"d","text":"الركض بين الطوابق بأقصى سرعة"}]'::jsonb, 'b', 'السلوك الآمن هو الاحتماء تحت طاولة متينة وحماية الرأس والابتعاد عن النوافذ. أمّا الوقوف قرب الزجاج فيعرّض للجروح، واستعمال المصعد خطر لأنّه قد يتوقّف، والركض بين الطوابق يزيد خطر السقوط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5196e4a6-7147-5b9c-b857-57526d7a7ea5', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ما الموجة الزلزالية الأكثر تدميرًا للمباني عادةً؟', '[{"id":"a","text":"الموجات الأوّلية (P)"},{"id":"b","text":"الموجات السطحية"},{"id":"c","text":"لا توجد موجة أكثر تدميرًا من غيرها"},{"id":"d","text":"الموجات الصوتية في الهواء"}]'::jsonb, 'b', 'الموجات السطحية تنتشر قرب السطح وتُحدث اهتزازات قويّة فهي الأكثر تدميرًا للمباني، رغم أنّ الموجات P تصل أوّلًا. والموجات الصوتية في الهواء ليست موجات زلزالية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9c0751c-3098-59c2-9b2b-5866a95f73e8', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'أيّ ظاهرة قد تنتج عن زلزال قويّ يقع في قاع البحر؟', '[{"id":"a","text":"تسونامي (موجات بحرية عملاقة)"},{"id":"b","text":"كسوف للشمس"},{"id":"c","text":"هطول ثلوج كثيفة"},{"id":"d","text":"تكوّن قوس قزح"}]'::jsonb, 'a', 'الزلزال القويّ في قاع البحر قد يزيح كتلة ضخمة من الماء فجأة فينشأ التسونامي: موجات بحرية عملاقة قد تجتاح السواحل. أمّا الكسوف والثلوج وقوس قزح فظواهر لا علاقة لها بالزلازل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('13fb75ad-e954-5336-97b3-69221d649f56', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'أيّ إجراء بناء يقلّل فعليًّا من أضرار الزلازل؟', '[{"id":"a","text":"تشييد مبانٍ مقاومة للزلازل وفق معايير مضادّة للهزّات"},{"id":"b","text":"البناء مباشرةً فوق الفوالق النشطة"},{"id":"c","text":"استعمال مواد هشّة لتخفيف وزن المبنى"},{"id":"d","text":"إلغاء أيّ معايير في البناء لتسريع الإنجاز"}]'::jsonb, 'a', 'البناء المقاوم للزلازل وفق معايير مضادّة للهزّات يقلّل الأضرار فعليًّا. أمّا البناء فوق الفوالق النشطة أو استعمال مواد هشّة أو إلغاء المعايير فكلّها تزيد الخطر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46aedd13-e330-51e4-852a-e36919f88ee8', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'زلزال سُجّل مقداره 6 على سلّم ريشتر، وقيست له شدّات مختلفة في عدّة مدن. ما التفسير الصحيح؟', '[{"id":"a","text":"خطأ في القياس لأنّ كلّ القيم يجب أن تتطابق"},{"id":"b","text":"المقدار قيمة واحدة (الطاقة عند البؤرة)، بينما تختلف الشدّة من مدينة لأخرى حسب الآثار"},{"id":"c","text":"المقدار يجب أن يختلف هو الآخر من مدينة لأخرى"},{"id":"d","text":"الشدّة والمقدار يقيسان نفس الشيء فلا يمكن اختلافهما"}]'::jsonb, 'b', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة (6 هنا) في كلّ المدن، بينما تقيس الشدّة آثار الزلزال على السطح فتختلف من مدينة لأخرى حسب القرب من المركز السطحي ونوع التربة وجودة البناء. فلا تناقض في ذلك.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d98981a-72a1-59f9-8c58-6216ca3fb14d', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ربط منطقي: لماذا يساعد امتلاك شبكة مراصد زلزالية متعدّدة على الوقاية؟', '[{"id":"a","text":"لأنّها تمنع وقوع الزلازل نهائيًّا"},{"id":"b","text":"لأنّها تحدّد مواقع الزلازل وتراقب النشاط الزلزالي فتدعم الإنذار المبكّر وخرائط المخاطر"},{"id":"c","text":"لأنّها ترفع مقدار الزلزال فتقلّل أضراره"},{"id":"d","text":"لأنّها تغيّر اتّجاه الموجات الزلزالية بعيدًا عن المدن"}]'::jsonb, 'b', 'شبكة المراصد تحدّد مواقع الزلازل (المركز السطحي) عبر فرق وصول الموجات وتراقب النشاط الزلزالي، فتدعم الإنذار المبكّر ورسم خرائط المخاطر والتخطيط العمراني. لكنّها لا تمنع الزلازل ولا تغيّر مقدارها ولا تحرف الموجات؛ دورها الرصد والوقاية لا التحكّم في الظاهرة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9b5651b1-1a26-5a20-baa1-d7a19a32cd94', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f8f6110-6f58-54b0-9ecb-932213bf4320', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما هو البركان؟', '[{"id":"a","text":"اهتزاز مفاجئ لسطح الأرض ناتج عن تحرّر طاقة في باطنها"},{"id":"b","text":"فُتحة في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة من باطن الأرض"},{"id":"c","text":"صخر منصهر يبقى دائمًا حبيس باطن الأرض"},{"id":"d","text":"تجويف على سطح الأرض تجمّع فيه ماء المطر"}]'::jsonb, 'b', 'البركان فُتحة (أو شقّ) في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة آتية من العمق. أمّا الاهتزاز المفاجئ للأرض فهو الزلزال لا البركان، والصهارة الحبيسة دائمًا في الباطن ليست بركانًا لأنّ البركان يتطلّب خروج الموادّ إلى السطح.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('799a06e3-775f-5fd8-af12-64f0252d41df', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أين تتجمّع الصهارة قبل صعودها نحو سطح الأرض؟', '[{"id":"a","text":"في الفوّهة"},{"id":"b","text":"في المخروط البركاني"},{"id":"c","text":"في الخزّان الصهاري (الغرفة الصهارية)"},{"id":"d","text":"في الرماد البركاني"}]'::jsonb, 'c', 'تتجمّع الصهارة في الخزّان الصهاري الموجود في العمق، ثمّ تصعد عبر المدخنة إلى الفوّهة فالسطح. الفوّهة هي الفتحة العلوية، والمخروط هو الجبل المتراكم خارجًا، فلا يصحّ أيّ منهما مكانًا لتجمّع الصهارة قبل الصعود.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73b75412-8e4a-59d0-9a2c-e2712b129445', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما الذي يميّز الثوران البركاني الانسيابي (الهادئ)؟', '[{"id":"a","text":"انفجار عنيف يقذف سحبًا حارقة من الرماد والكُتل"},{"id":"b","text":"خروج اللابة السائلة بهدوء وسيلانها على شكل أنهار من الحِمم"},{"id":"c","text":"عدم خروج أيّ مادّة من الفوّهة"},{"id":"d","text":"خروج الماء فقط دون لابة"}]'::jsonb, 'b', 'في الثوران الانسيابي تكون الصهارة سائلة قليلة اللزوجة، فتخرج اللابة بهدوء وتسيل بعيدًا مكوّنةً أنهارًا من الحِمم ومخروطًا منبسطًا. أمّا الانفجار العنيف وقذف السُحب الحارقة فهو سمة الثوران الانفجاري لا الانسيابي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('201daf6e-3c9f-5acd-a33c-ed2fb316b2b2', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ ممّا يلي يُعدّ فائدة من فوائد البراكين للإنسان؟', '[{"id":"a","text":"خصوبة التربة البركانية والطاقة الحرارية الأرضية (الجيوحرارية)"},{"id":"b","text":"تدمير المنشآت بالحِمم"},{"id":"c","text":"خنق الكائنات الحيّة بالرماد"},{"id":"d","text":"تلوّث الهواء بالغازات"}]'::jsonb, 'a', 'من فوائد البراكين خصوبة تربتها وتوفير الطاقة الجيوحرارية والثروات المعدنية وينابيع المياه الساخنة. أمّا تدمير المنشآت وخنق الكائنات بالرماد وتلوّث الهواء فهي من مخاطر البراكين لا فوائدها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85dff667-cdd6-5b2a-8a36-8e98376e11d7', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما الفرق الأساسي بين الصهارة (Magma) واللابة (Lave)؟', '[{"id":"a","text":"الصهارة في باطن الأرض ومحمّلة بالغازات، واللابة هي الصهارة نفسها بعد خروجها إلى السطح وفقدها معظم غازاتها"},{"id":"b","text":"اللابة في باطن الأرض، والصهارة على سطحها"},{"id":"c","text":"الصهارة صلبة دائمًا، واللابة غاز"},{"id":"d","text":"هما مادّتان مختلفتان تمامًا لا علاقة بينهما"}]'::jsonb, 'a', 'الصهارة صخر منصهر محمّل بالغازات يوجد في باطن الأرض، واللابة هي الصهارة ذاتها بعد خروجها إلى السطح وقد فقدت معظم غازاتها. فالعلاقة بينهما واحدة: نفس المادّة قبل الخروج (صهارة) وبعده (لابة)، لذا فالقول إنّهما مختلفتان تمامًا أو إنّ اللابة في الباطن خطأ شائع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3359ec63-90e2-5cf0-a769-94dd37b4dfab', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ نوع من الصهارة يميّز الثوران البركاني الانفجاري (المتفجّر)؟', '[{"id":"a","text":"صهارة سائلة قليلة اللزوجة وفقيرة بالغازات"},{"id":"b","text":"صهارة لزجة (كثيفة) غنيّة بالغازات"},{"id":"c","text":"صهارة باردة صلبة"},{"id":"d","text":"ماء ساخن مشبّع بالأملاح"}]'::jsonb, 'b', 'الثوران الانفجاري ينتج عن صهارة لزجة غنيّة بالغازات: تَسُدّ اللزوجة المدخنة فيتراكم ضغط الغازات حتى ينفجر البركان. أمّا الصهارة السائلة القليلة اللزوجة فتعطي ثورانًا انسيابيًّا هادئًا، وهذا هو الخلط الشائع بين النوعين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f0aef35-b057-5f8b-b7ef-6420a0ef20c8', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ المجموعات التالية تمثّل المقذوفات البركانية الثلاثة؟', '[{"id":"a","text":"موادّ سائلة (لابة) + موادّ غازية + موادّ صلبة (رماد وكُتل)"},{"id":"b","text":"ماء + هواء + تراب فقط"},{"id":"c","text":"غازات فقط لا غير"},{"id":"d","text":"صخور صلبة باردة فقط"}]'::jsonb, 'a', 'يقذف البركان ثلاثة أصناف: موادّ سائلة (اللابة)، وموادّ غازية (بخار الماء وثاني أكسيد الكربون وغيرها)، وموادّ صلبة (الرماد والحصى والقنابل البركانية). فحصْرها في الغازات وحدها أو الصخور الباردة وحدها غير صحيح.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1deecf3f-237a-5fb9-91b7-3d550ac1456b', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'كيف تتوزّع البراكين على سطح الأرض؟', '[{"id":"a","text":"توزّعًا عشوائيًّا متساويًا في كلّ مكان"},{"id":"b","text":"في المناطق القطبية الباردة فقط"},{"id":"c","text":"تتركّز على طول حدود الصفائح التكتونية (مثل حزام النار حول المحيط الهادئ)"},{"id":"d","text":"في وسط القارّات بعيدًا عن أيّ حدود"}]'::jsonb, 'c', 'لا تتوزّع البراكين عشوائيًّا، بل تتركّز أساسًا على حدود الصفائح التكتونية، وأشهرها حزام النار المحيط بالمحيط الهادئ. هذا التركّز يدلّ على ارتباط النشاط البركاني بحركة الصفائح، فلا يصحّ القول إنّه عشوائي أو محصور في القطبين.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

