  ('2eed667c-8445-52e3-93cd-5803e6592d72', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', 'تمرين: البركان وبنيته والصهارة', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
