  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e1eb424-4dcd-5f84-a9db-0cf9938f6633', '2eed667c-8445-52e3-93cd-5803e6592d72', 'القناة الشاقولية التي تصعد عبرها الموادّ من الخزّان الصهاري نحو السطح تُسمّى:', '[{"id":"a","text":"الفوّهة"},{"id":"b","text":"المدخنة (المجرى)"},{"id":"c","text":"المخروط البركاني"},{"id":"d","text":"الخزّان الصهاري"}]'::jsonb, 'b', 'المدخنة هي القناة التي تصعد فيها الموادّ من الخزّان الصهاري إلى الفوّهة. الفوّهة هي الفتحة العلوية التي تخرج منها المقذوفات، والخزّان مكان تجمّع الصهارة في العمق، والمخروط هو الجبل المتراكم خارجًا؛ فلا ينطبق أيّ منها على قناة الصعود.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91872dd1-5150-522b-929d-f457bc287302', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الفتحة العلوية للبركان التي تخرج منها المقذوفات تُسمّى:', '[{"id":"a","text":"الخزّان الصهاري"},{"id":"b","text":"المدخنة"},{"id":"c","text":"الفوّهة"},{"id":"d","text":"اللابة"}]'::jsonb, 'c', 'الفوّهة هي الفتحة العلوية للبركان التي تخرج منها اللابة والغازات والموادّ الصلبة. الخزّان والمدخنة يقعان تحت الفوّهة، واللابة مادّة لا جزء من بنية البركان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46f41086-fc21-5e04-8a1b-5c67288323bb', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الصخر المنصهر المحمّل بالغازات والموجود في باطن الأرض يُسمّى:', '[{"id":"a","text":"اللابة"},{"id":"b","text":"الصهارة (Magma)"},{"id":"c","text":"الرماد البركاني"},{"id":"d","text":"القنبلة البركانية"}]'::jsonb, 'b', 'الصخر المنصهر المحمّل بالغازات داخل باطن الأرض هو الصهارة. حين يخرج إلى السطح ويفقد معظم غازاته يصبح اسمه اللابة، أمّا الرماد والقنابل فهي موادّ صلبة مقذوفة وليست الصخر المنصهر في العمق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0cd1a2f1-af5d-5cc9-9510-111e897dbba0', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الصهارة بعد خروجها إلى سطح الأرض وفقدها معظم غازاتها تُسمّى:', '[{"id":"a","text":"اللابة (الحِمم)"},{"id":"b","text":"الصهارة"},{"id":"c","text":"المدخنة"},{"id":"d","text":"الخزّان الصهاري"}]'::jsonb, 'a', 'بمجرّد خروج الصهارة إلى السطح وفقدها معظم غازاتها يتغيّر اسمها إلى اللابة (الحِمم). فلو بقيت في الداخل لظلّت تُسمّى صهارة. المدخنة والخزّان عنصران من بنية البركان لا أسماء للمادّة المنصهرة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('058d7fe8-2ddc-5ef2-9f17-cf1840b56532', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الجبل المخروطي الذي يتكوّن من تراكم المقذوفات حول الفوّهة يُسمّى:', '[{"id":"a","text":"الخزّان الصهاري"},{"id":"b","text":"المخروط البركاني"},{"id":"c","text":"المدخنة"},{"id":"d","text":"الصهارة"}]'::jsonb, 'b', 'تراكم المقذوفات (لابة ورماد وكُتل) حول الفوّهة عبر الزمن يبني المخروط البركاني ذا الشكل الجبلي. الخزّان والمدخنة في العمق، والصهارة مادّة وليست بنية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87d0c151-b937-5a15-aa00-ff95b7c8c531', '2eed667c-8445-52e3-93cd-5803e6592d72', 'أيّ ترتيب يصف صعود الموادّ في البركان من العمق إلى السطح صعودًا صحيحًا؟', '[{"id":"a","text":"الفوّهة ← المدخنة ← الخزّان الصهاري"},{"id":"b","text":"المدخنة ← الفوّهة ← الخزّان الصهاري"},{"id":"c","text":"الخزّان الصهاري ← المدخنة ← الفوّهة"},{"id":"d","text":"الخزّان الصهاري ← الفوّهة ← المدخنة"}]'::jsonb, 'c', 'تبدأ الموادّ من الخزّان الصهاري في العمق، ثمّ تصعد عبر المدخنة، فتخرج أخيرًا من الفوّهة إلى السطح. أيّ ترتيب يضع الفوّهة قبل المدخنة أو الخزّان في الأعلى يعكس مسار الصعود الحقيقي.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6c750cda-b071-5a1b-aaa4-20510a92cdee', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', 'تمرين: أنواع الثورات والمقذوفات والتوزّع', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('033d5aed-f9c4-54d1-ad9f-4cbd5ed6071d', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'البركان الذي تخرج منه لابة سائلة تسيل بهدوء على شكل أنهار من الحِمم يكون ثورانه:', '[{"id":"a","text":"انفجاريًّا متفجّرًا"},{"id":"b","text":"انسيابيًّا هادئًا"},{"id":"c","text":"زلزاليًّا"},{"id":"d","text":"معدومًا"}]'::jsonb, 'b', 'سيلان اللابة السائلة بهدوء على شكل أنهار من الحِمم سمة الثوران الانسيابي الهادئ الناتج عن صهارة قليلة اللزوجة. الثوران الانفجاري يقذف رمادًا وكُتلًا بعنف، والزلزال ظاهرة أخرى لا نوع ثوران بركاني.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90d644e7-11db-5627-9a31-b5a8d55b3ac0', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ ممّا يلي من المقذوفات الصلبة للبركان؟', '[{"id":"a","text":"اللابة السائلة"},{"id":"b","text":"بخار الماء"},{"id":"c","text":"الرماد البركاني والقنابل البركانية"},{"id":"d","text":"ثاني أكسيد الكربون"}]'::jsonb, 'c', 'الرماد البركاني والكُتل الصخرية (القنابل البركانية) هي موادّ صلبة مقذوفة. اللابة مادّة سائلة، وبخار الماء وثاني أكسيد الكربون موادّ غازية، فهي لا تُعدّ مقذوفات صلبة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2962615-64e1-5d14-b588-f291251efb4d', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'العامل الأساسي الذي يحدّد ما إذا كان الثوران هادئًا أم انفجاريًّا هو:', '[{"id":"a","text":"لون المخروط البركاني"},{"id":"b","text":"ارتفاع الجبل البركاني فقط"},{"id":"c","text":"لزوجة الصهارة وكمّية الغازات فيها"},{"id":"d","text":"الوقت من السنة"}]'::jsonb, 'c', 'طبيعة الثوران تتوقّف على لزوجة الصهارة وكمّية الغازات: الصهارة السائلة القليلة الغازات تعطي ثورانًا هادئًا، واللزجة الغنيّة بالغازات تعطي ثورانًا انفجاريًّا. أمّا لون المخروط أو ارتفاعه أو الفصل فلا علاقة لها بنوع الثوران.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4215d9f8-e89a-5df6-b234-824021e596fe', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'تتركّز معظم براكين العالم النشطة على طول:', '[{"id":"a","text":"خطّ الاستواء فقط"},{"id":"b","text":"حدود الصفائح التكتونية (مثل حزام النار حول المحيط الهادئ)"},{"id":"c","text":"وسط الصحاري الكبرى"},{"id":"d","text":"القطبين الشمالي والجنوبي"}]'::jsonb, 'b', 'ترتبط البراكين بحركة الصفائح، لذلك تتركّز على حدودها، وأشهر تجمّع هو حزام النار حول المحيط الهادئ. لا علاقة لتوزّعها بخطّ الاستواء أو الصحاري أو القطبين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f0bc02e-9def-5196-ab64-16519288cc10', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ زوج يربط نوع الصهارة بنوع الثوران ربطًا صحيحًا؟', '[{"id":"a","text":"صهارة سائلة قليلة الغازات ← ثوران انفجاري"},{"id":"b","text":"صهارة لزجة غنيّة بالغازات ← ثوران هادئ"},{"id":"c","text":"صهارة لزجة غنيّة بالغازات ← ثوران انفجاري"},{"id":"d","text":"صهارة باردة صلبة ← ثوران هادئ"}]'::jsonb, 'c', 'الصهارة اللزجة الغنيّة بالغازات تسدّ المدخنة ويتراكم الضغط فيحدث ثوران انفجاري، بينما الصهارة السائلة القليلة الغازات تعطي ثورانًا هادئًا. لذلك ربط السائلة بالانفجار أو اللزجة بالهدوء خلط شائع بين النوعين، والصهارة الباردة الصلبة لا تثور أصلًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9035b2de-9933-55e8-a9ea-1f34c6a24c87', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ مقذوف بركاني يُعدّ خطرًا كبيرًا على حركة الطيران ويمتدّ أثره إلى مسافات بعيدة؟', '[{"id":"a","text":"اللابة السائلة"},{"id":"b","text":"الرماد البركاني المتطاير في الجوّ"},{"id":"c","text":"المخروط البركاني"},{"id":"d","text":"الخزّان الصهاري"}]'::jsonb, 'b', 'الرماد البركاني الدقيق يتطاير ويرتفع في الجوّ وينتشر لمسافات بعيدة، فيُعطّل حركة الطيران ويخنق الكائنات ويلوّث الهواء. اللابة خطرها محلّي حول البركان، والمخروط والخزّان عنصران من بنية البركان لا مقذوفات متطايرة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2d7eca62-3226-5a2d-8889-aabec2c0455f', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', '⚔️ زعيم الفصل: البراكين', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3ccda48-8108-560a-ac1e-a9c88ec15449', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'تلميذ قال: «اللابة هي الصخر المنصهر داخل الخزّان الصهاري، والصهارة هي ما يخرج إلى السطح». ما الصواب؟', '[{"id":"a","text":"كلامه صحيح تمامًا"},{"id":"b","text":"العكس هو الصحيح: الصهارة في الباطن، واللابة ما يخرج إلى السطح"},{"id":"c","text":"الاسمان مترادفان ولا فرق بينهما"},{"id":"d","text":"كلاهما يوجد في الجوّ فقط"}]'::jsonb, 'b', 'التلميذ عكس المفهومين: الصهارة (Magma) هي الصخر المنصهر المحمّل بالغازات في باطن الأرض، واللابة (Lave) هي الصهارة نفسها بعد خروجها إلى السطح وفقدها معظم غازاتها. وهما ليسا مترادفين تمامًا لأنّ الموقع وكمّية الغازات تختلف، ولا يوجدان في الجوّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58e6ae8a-7817-57f7-b9b6-0848595b0089', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'بركان صهارته لزجة جدًّا وغنيّة بالغازات. ما السلوك المتوقّع لثورانه ولماذا؟', '[{"id":"a","text":"ثوران هادئ لأنّ اللابة ستسيل بسهولة"},{"id":"b","text":"ثوران انفجاري لأنّ اللزوجة تَسُدّ المدخنة فيتراكم ضغط الغازات حتى ينفجر"},{"id":"c","text":"لن يثور أبدًا لأنّ الصهارة لزجة"},{"id":"d","text":"سيُخرج ماءً عذبًا فقط"}]'::jsonb, 'b', 'اللزوجة العالية تعيق صعود الصهارة فتَسُدّ المدخنة، ومع غناها بالغازات يتراكم الضغط حتى ينفجر البركان قاذفًا رمادًا وكُتلًا وسُحبًا حارقة. فالصهارة اللزجة الغنيّة بالغازات لا تعطي ثورانًا هادئًا، وهي تثور بعنف لا أنّها لا تثور.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a93265fd-b2b3-5a76-9491-ba4afd59a9d8', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'لماذا تتراصف البراكين والزلازل غالبًا في الأحزمة نفسها على الكرة الأرضية؟', '[{"id":"a","text":"لأنّها ظواهر عشوائية بحتة"},{"id":"b","text":"لأنّ كليهما مرتبط بحركة الصفائح التكتونية على حدودها"},{"id":"c","text":"لأنّها تحدث فقط في المناطق الباردة"},{"id":"d","text":"لأنّ سبب البراكين هو المطر الغزير"}]'::jsonb, 'b', 'تتركّز البراكين والزلازل على حدود الصفائح لأنّ كليهما من مظاهر النشاط الباطني المرتبط بحركة هذه الصفائح وتفاعلها (تقارب وتباعد). فالأمر ليس عشوائيًّا ولا مرتبطًا بالبرودة أو المطر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a331edff-ffe9-58f7-869f-9561a036e357', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'أيّ مقارنة بين الثوران الانسيابي والانفجاري صحيحة؟', '[{"id":"a","text":"الانسيابي مخروطه منبسط وحممه سائلة، والانفجاري أعنف ويقذف رمادًا وكُتلًا"},{"id":"b","text":"الانسيابي هو الأخطر دائمًا، والانفجاري لا يقذف شيئًا"},{"id":"c","text":"كلاهما يقذف لابة سائلة فقط دون غازات"},{"id":"d","text":"الانفجاري حممه سائلة تسيل بهدوء بعيدًا"}]'::jsonb, 'a', 'الثوران الانسيابي ناتج عن صهارة سائلة تعطي مخروطًا منبسطًا وحممًا تسيل بهدوء، أمّا الانفجاري فأعنف ويقذف رمادًا وكُتلًا وسُحبًا حارقة وهو الأخطر. فلا يصحّ نسبة الخطورة الأكبر للانسيابي ولا نسبة السيلان الهادئ للانفجاري.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('737a946e-6748-551e-8d47-63dfb113feb4', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'تجمّعت سحابة من الرماد البركاني الدقيق وانتشرت لمئات الكيلومترات بعد ثوران. أيّ المخاطر التالية الأكثر ارتباطًا بهذه السحابة؟', '[{"id":"a","text":"خصوبة فورية للتربة دون أيّ ضرر"},{"id":"b","text":"تعطيل حركة الطيران واختناق الكائنات وتلوّث الهواء"},{"id":"c","text":"تبريد سطح الأرض إلى درجة التجمّد فورًا"},{"id":"d","text":"توليد الكهرباء مباشرةً للمنازل"}]'::jsonb, 'b', 'الرماد المتطاير الدقيق يعطّل محرّكات الطائرات ويعيق الرؤية ويخنق الكائنات الحيّة ويلوّث الهواء عبر مسافات بعيدة، وهذه من أخطر آثار البراكين الانفجارية. أمّا خصوبة التربة فأثر لاحق طويل الأمد لا يلغي الخطر، والرماد لا يجمّد الأرض فورًا ولا يولّد كهرباء مباشرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c21355cf-f901-5dc2-8890-42c54d1f1da7', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'وُجد في إقليم تربة بركانية خصبة وينابيع مياه ساخنة ومحطّة طاقة جيوحرارية. ما العلاقة الصحيحة بهذه المعطيات؟', '[{"id":"a","text":"هي كلّها من فوائد النشاط البركاني للإنسان"},{"id":"b","text":"هي كلّها أضرار يجب التخلّص منها"},{"id":"c","text":"لا علاقة لها بالبراكين إطلاقًا"},{"id":"d","text":"هي دليل على غياب أيّ نشاط باطني"}]'::jsonb, 'a', 'التربة البركانية الخصبة والمياه الساخنة والطاقة الجيوحرارية كلّها من فوائد النشاط البركاني التي يستثمرها الإنسان. فهي ليست أضرارًا، ووجودها مرتبط مباشرةً بالنشاط الباطني البركاني لا دليلًا على غيابه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ed7f3893-2d09-5646-9952-83b2d24d51a0', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', '👑 تحدّي النخبة: البراكين — تحليل وتفسير', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f6bb2dd-68da-59a1-b432-76024b357baa', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'بركانان: الأوّل مخروطه شديد الانحدار وثوراناته تقذف رمادًا وكُتلًا بعنف، والثاني مخروطه منبسط واسع وحممه تسيل بهدوء لمسافات بعيدة. ما الاستنتاج الأصحّ حول صهارة كلّ منهما؟', '[{"id":"a","text":"صهارة الأوّل لزجة غنيّة بالغازات، وصهارة الثاني سائلة قليلة الغازات"},{"id":"b","text":"صهارة الأوّل سائلة قليلة الغازات، وصهارة الثاني لزجة غنيّة بالغازات"},{"id":"c","text":"صهارتهما متطابقتان والفرق صدفة فقط"},{"id":"d","text":"لا علاقة بين شكل المخروط ونوع الصهارة"}]'::jsonb, 'a', 'المخروط الشديد الانحدار مع القذف العنيف يدلّ على صهارة لزجة غنيّة بالغازات (ثوران انفجاري)، بينما المخروط المنبسط مع سيلان الحِمم بهدوء يدلّ على صهارة سائلة قليلة الغازات (ثوران انسيابي). فشكل المخروط وسلوك الثوران مرتبطان مباشرةً بطبيعة الصهارة لا بالصدفة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e127f7d2-ed74-5711-aab1-ef76138e83dc', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'خريطة عالمية تُظهر تطابقًا كبيرًا بين مواقع البراكين النشطة ومواقع الزلازل القوية على شكل أحزمة. ما التفسير العلمي لهذا التطابق؟', '[{"id":"a","text":"الزلازل هي التي تنتج البراكين بشكل مباشر"},{"id":"b","text":"كلتا الظاهرتين من مظاهر النشاط الباطني المرتبط بحركة الصفائح على حدودها"},{"id":"c","text":"التطابق محض مصادفة لا معنى لها"},{"id":"d","text":"البراكين تتبع توزّع المدن الكبرى"}]'::jsonb, 'b', 'تطابق أحزمة البراكين والزلازل يُفسَّر بأنّ كليهما من مظاهر النشاط الباطني عند حدود الصفائح التكتونية حيث تتفاعل الصفائح (تقاربًا وتباعدًا). فليست الزلازل سببًا مباشرًا في توليد البراكين، والتطابق ليس مصادفة ولا علاقة له بتوزّع المدن.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa94d3c6-f437-5122-95f0-91b8ae58ae4e', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'لاحظ سكّان أنّ غازات البركان وبخار الماء تتصاعد بهدوء من الفوّهة لأسابيع دون قذف رماد أو كُتل، وأنّ سطح الحمم في الفوّهة سائل ومتوهّج. ما النوع الأرجح لهذا البركان؟', '[{"id":"a","text":"بركان انفجاري شديد الخطورة على وشك الانفجار حتمًا"},{"id":"b","text":"بركان انسيابي هادئ صهارته سائلة تسمح بتحرّر الغازات تدريجيًّا"},{"id":"c","text":"بركان خامد لا نشاط فيه إطلاقًا"},{"id":"d","text":"ليس بركانًا بل مجرّد ينبوع ماء ساخن"}]'::jsonb, 'b', 'تحرّر الغازات تدريجيًّا بهدوء ووجود حمم سائلة متوهّجة دون قذف عنيف مؤشّرات على ثوران انسيابي هادئ، لأنّ الصهارة السائلة تسمح للغازات بالإفلات دون تراكم ضغط انفجاري. فلا يدلّ ذلك على انفجار حتمي، ووجود نشاط ظاهر ينفي كونه خامدًا أو مجرّد ينبوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('819005be-7c71-5cfd-9b1e-4959abc4c98d', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'بعد سنوات من ثوران انفجاري، أصبحت أراضي المنطقة من أخصب الأراضي الزراعية رغم الدمار الذي خلّفه الثوران. ما التفسير العلمي الذي يجمع بين الضرر والفائدة؟', '[{"id":"a","text":"البراكين مفيدة فقط ولا ضرر لها على الإطلاق"},{"id":"b","text":"البراكين ضارّة فقط، والخصوبة لا علاقة لها بها"},{"id":"c","text":"للبركان مخاطر آنية (دمار ورماد) وفوائد لاحقة كإغناء التربة بالمعادن من موادّه"},{"id":"d","text":"الخصوبة سببها توقّف المطر بعد الثوران"}]'::jsonb, 'c', 'للبراكين وجهان: مخاطر آنية (دمار وحرائق ورماد) وفوائد لاحقة، إذ تغني موادّ البركان (الرماد واللابة المتحلّلة) التربة بالمعادن فتجعلها خصبة مع الزمن. فلا يصحّ حصْره في الفائدة وحدها أو الضرر وحده، والخصوبة سببها معادن البركان لا توقّف المطر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5717bc09-d510-5b10-8363-d57b551b158c', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'لماذا تكون اللابة الخارجة من البركان أفقر بالغازات من الصهارة التي كانت في الخزّان الصهاري؟', '[{"id":"a","text":"لأنّ الغازات تتحرّر وتنطلق إلى الجوّ أثناء صعود الصهارة وخروجها إلى السطح"},{"id":"b","text":"لأنّ الصهارة تكتسب غازات إضافية عند الخروج"},{"id":"c","text":"لأنّ اللابة لا تحتوي غازات أصلًا في أيّ مرحلة"},{"id":"d","text":"لأنّ الخزّان الصهاري لا يحتوي أيّ غازات"}]'::jsonb, 'a', 'مع انخفاض الضغط أثناء صعود الصهارة نحو السطح تتحرّر الغازات الذائبة وتنطلق إلى الجوّ، فتخرج اللابة وقد فقدت معظم غازاتها. فالصهارة لا تكتسب غازات عند الخروج، والخزّان غنيّ بالغازات أصلًا، وهي السبب في ذلك الفرق.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40ec4025-fa54-56d3-b309-a256d5da58ff', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'مدينتان قرب بركان واحد: الأولى في وادٍ منخفض على مسار سيلان الحمم، والثانية على مرتفع بعيد لكنّها في اتّجاه الرياح السائدة. أيّ خطر أبرز يهدّد كلّ مدينة؟', '[{"id":"a","text":"الأولى تهدّدها الحمم السائلة، والثانية يهدّدها الرماد المتطاير الذي تحمله الرياح"},{"id":"b","text":"الأولى يهدّدها الرماد فقط، والثانية الحمم فقط"},{"id":"c","text":"لا خطر على أيّ منهما ما دامتا قرب البركان"},{"id":"d","text":"كلتاهما مهدّدة فقط بالزلازل لا بالبركان"}]'::jsonb, 'a', 'الحمم السائلة تنحدر مع الجاذبية نحو المناطق المنخفضة فتهدّد المدينة في الوادي، بينما الرماد المتطاير الدقيق تحمله الرياح إلى المناطق الواقعة في اتّجاهها ولو كانت بعيدة ومرتفعة، فيهدّد المدينة الثانية. فلا يصحّ عكس الخطرين ولا نفيهما، والخطر هنا بركاني لا زلزالي.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('42259663-22a3-56ae-b44a-a0d2fe940ce8', '19515433-2bba-541b-9762-67c03842195a', 'sciences-vie-terre', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
