  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8ba0dd0-a06a-509c-a588-0e0d5cfee8a2', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما ترتيب طبقات الكرة الأرضية من السطح نحو المركز؟', '[{"id":"a","text":"النواة ثمّ الوشاح ثمّ القشرة"},{"id":"b","text":"القشرة ثمّ الوشاح ثمّ النواة"},{"id":"c","text":"الوشاح ثمّ القشرة ثمّ النواة"},{"id":"d","text":"القشرة ثمّ النواة ثمّ الوشاح"}]'::jsonb, 'b', 'من السطح نحو العمق نجد: القشرة الأرضية (طبقة خارجية رقيقة صلبة)، ثمّ الوشاح (طبقة سميكة جدًّا)، ثمّ النواة في المركز. القشرة هي الأقرب إلينا والنواة هي الأعمق.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5593f4a-b80d-5f5c-a5f9-8e3d3c487c73', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما اسم القارّة العملاقة الواحدة التي افترض فاجنر أنّ القارّات انفصلت عنها؟', '[{"id":"a","text":"الأسثينوسفير"},{"id":"b","text":"الظهرة"},{"id":"c","text":"بانجيا (Pangée)"},{"id":"d","text":"الليثوسفير"}]'::jsonb, 'c', 'اقترح ألفريد فاجنر أنّ القارّات كانت ملتصقة في قارّة عملاقة واحدة سمّاها «بانجيا»، ثمّ تباعدت تدريجيًّا (نظرية انجراف القارّات).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d41b4048-cd3f-5fb2-897c-d9de3e51430e', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'أين تتركّز معظم الزلازل والبراكين على سطح الأرض؟', '[{"id":"a","text":"في وسط الصفائح بعيدًا عن حدودها"},{"id":"b","text":"على حدود الصفائح التكتونية"},{"id":"c","text":"في النواة الداخلية فقط"},{"id":"d","text":"بشكل متساوٍ في كلّ مكان من الأرض"}]'::jsonb, 'b', 'تتركّز معظم الزلازل والبراكين على حدود الصفائح (الظهرات ومناطق الطمر) حيث تحتكّ الصفائح وتتحرّك، لا في وسطها. ومن أمثلة ذلك حزام النار المحيط بالمحيط الهادئ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d917dacf-423c-52dc-ac0a-743e9cddf713', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما الفرق بين القشرة القارّية والقشرة المحيطية؟', '[{"id":"a","text":"القشرة القارّية أرقّ وأكثر كثافة من المحيطية"},{"id":"b","text":"القشرة المحيطية أسمك وأقلّ كثافة من القارّية"},{"id":"c","text":"القشرة القارّية أسمك وأقلّ كثافة، والمحيطية أرقّ وأكثر كثافة"},{"id":"d","text":"لا فرق بينهما؛ هما طبقة واحدة"}]'::jsonb, 'c', 'القشرة القارّية سميكة (نحو 30–70 كم) وأقلّ كثافة (غرانيتية)، أمّا القشرة المحيطية فرقيقة (نحو 5–10 كم) وأكثر كثافة (بازلتية). هذا الفرق في الكثافة هو الذي يجعل القشرة المحيطية تغوص تحت القارّية عند الطمر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('219e410f-acb9-568f-a714-090de5f57ba4', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ممّ يتكوّن الليثوسفير (الغلاف الصخري)؟', '[{"id":"a","text":"من القشرة وحدها"},{"id":"b","text":"من القشرة + الجزء العلوي الصلب من الوشاح"},{"id":"c","text":"من الوشاح والنواة معًا"},{"id":"d","text":"من الأسثينوسفير اللزج فقط"}]'::jsonb, 'b', 'الليثوسفير صلب ويشمل القشرة والجزء العلوي الصلب من الوشاح معًا، وهو المجزّأ إلى صفائح تكتونية. لذلك الصفيحة ليست القشرة وحدها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5468bcb-f60a-5c91-9afc-5db6bdeb4a49', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'أيّ ممّا يلي يُعدّ دليلًا استند إليه فاجنر على انجراف القارّات؟', '[{"id":"a","text":"وجود المتحجّرات نفسها على قارّات تفصلها محيطات اليوم"},{"id":"b","text":"تساوي عدد سكّان القارّات"},{"id":"c","text":"تشابه ألوان مياه المحيطات"},{"id":"d","text":"تساوي درجات الحرارة في كلّ القارّات"}]'::jsonb, 'a', 'من أدلّة فاجنر وجود متحجّرات لكائنات نفسها على قارّات متباعدة اليوم، إضافة إلى تطابق السواحل وتواصل الصخور والجبال. وهذا يدلّ على أنّ القارّات كانت ملتصقة سابقًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cef65281-4f05-569e-b5e1-364a8ec75178', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ماذا يحدث عند الظهرة المحيطية؟', '[{"id":"a","text":"تغوص صفيحة تحت أخرى وتختفي القشرة"},{"id":"b","text":"تتباعد صفيحتان ويصعد الصهير فيكوّن قشرة محيطية جديدة"},{"id":"c","text":"تتوقّف الصفائح عن الحركة نهائيًّا"},{"id":"d","text":"تلتصق القارّات ببعضها من جديد"}]'::jsonb, 'b', 'الظهرة المحيطية حدود متباعدة: تتباعد عندها صفيحتان فيصعد الصهير من الوشاح ويبرد مكوّنًا قشرة محيطية جديدة. هذه ظاهرة التوسّع المحيطي، وبها تكون القشرة أحدث عند الظهرة وأقدم كلّما ابتعدنا.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9111412d-4b81-5ff8-9d9b-a2d421ad9169', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'في منطقة الطمر (الاندساس)، أيّ صفيحة تغوص تحت الأخرى؟', '[{"id":"a","text":"الصفيحة القارّية لأنّها أكثر كثافة"},{"id":"b","text":"الصفيحة المحيطية لأنّها أكثر كثافة"},{"id":"c","text":"الصفيحتان تصعدان معًا"},{"id":"d","text":"لا تغوص أيّ صفيحة"}]'::jsonb, 'b', 'عند تقارب صفيحتين تغوص الصفيحة المحيطية لأنّها أكثر كثافة من القارّية، فتندسّ داخل الوشاح. يصاحب ذلك خنادق محيطية وبراكين وزلازل قويّة عميقة.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

