INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2dbea48-9ac0-5174-bc1d-ce2cccdbd6cf', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'أيّ طبقة من طبقات الأرض هي الطبقة الخارجية الرقيقة الصلبة؟', '[{"id":"a","text":"النواة"},{"id":"b","text":"الوشاح"},{"id":"c","text":"القشرة الأرضية"},{"id":"d","text":"الأسثينوسفير"}]'::jsonb, 'c', 'القشرة الأرضية هي الطبقة الخارجية الرقيقة والصلبة التي نعيش عليها. أمّا الوشاح فطبقة سميكة جدًّا تحتها، والنواة في المركز. الخلط بين القشرة (رقيقة) والوشاح (سميك) خطأ شائع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9083b8c2-8fc9-5863-8737-0ae2c67cc6ff', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'ممّ تتكوّن نواة الأرض أساسًا؟', '[{"id":"a","text":"الغرانيت"},{"id":"b","text":"البازلت"},{"id":"c","text":"الماء"},{"id":"d","text":"الحديد والنيكل"}]'::jsonb, 'd', 'نواة الأرض معدنية تتكوّن أساسًا من الحديد والنيكل، ولها جزء خارجي سائل وجزء داخلي صلب. أمّا الغرانيت والبازلت فهما صخرا القشرة (القارّية والمحيطية).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c27846a2-6c7d-5135-8955-a22bc72311bf', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'بِمَ نسمّي الألواح الكبرى التي يتجزّأ إليها الليثوسفير؟', '[{"id":"a","text":"الصفائح التكتونية"},{"id":"b","text":"الظهرات المحيطية"},{"id":"c","text":"الخنادق"},{"id":"d","text":"المتحجّرات"}]'::jsonb, 'a', 'يتجزّأ الليثوسفير (الغلاف الصخري الصلب) إلى ألواح كبرى تُسمّى الصفائح التكتونية، وهي التي تتحرّك فوق الأسثينوسفير اللزج.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('272fd3b3-f59c-52c1-977f-30885bde42e2', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'من العالم الذي اقترح نظرية انجراف القارّات؟', '[{"id":"a","text":"نيوتن"},{"id":"b","text":"ألفريد فاجنر"},{"id":"c","text":"أينشتاين"},{"id":"d","text":"ريشتر"}]'::jsonb, 'b', 'اقترح العالم الألماني ألفريد فاجنر سنة 1912 نظرية انجراف القارّات. أمّا ريشتر فاسمه مرتبط بسلّم قياس مقدار الزلازل، وهو موضوع مختلف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a888759a-72ea-504f-952e-a407f8c793bb', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'فوق أيّ طبقة لزجة تتحرّك الصفائح التكتونية؟', '[{"id":"a","text":"النواة الصلبة"},{"id":"b","text":"القشرة القارّية"},{"id":"c","text":"الأسثينوسفير"},{"id":"d","text":"الظهرة المحيطية"}]'::jsonb, 'c', 'تتحرّك الصفائح (وهي من الليثوسفير الصلب) منزلقةً فوق الأسثينوسفير، وهو جزء من الوشاح العلوي لزج وقابل للتيّار. هذا التمييز بين الليثوسفير الصلب والأسثينوسفير اللزج أساسيّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
