  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eef18c7b-cdd8-5a27-bd28-11fc1ba1b078', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'ما القوّة المحرّكة لحركة الصفائح التكتونية؟', '[{"id":"a","text":"الرياح على سطح الأرض"},{"id":"b","text":"تيّارات الحمل الحراري في الوشاح"},{"id":"c","text":"أمواج البحر"},{"id":"d","text":"دوران القمر حول الأرض"}]'::jsonb, 'b', 'تتحرّك الصفائح بفعل تيّارات الحمل الحراري داخل الوشاح: المادّة الساخنة تصعد والباردة تنزل، فتجرّ الصفائح معها. وهذا هو المحرّك الذي عجز فاجنر عن تفسيره في البداية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

