INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ed463fd-8a58-5a34-8195-976595ab172f', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'الظهرة المحيطية هي:', '[{"id":"a","text":"خندق عميق تختفي عنده القشرة المحيطية"},{"id":"b","text":"سلسلة جبلية بركانية في وسط المحيط تتباعد عندها الصفائح"},{"id":"c","text":"سهل منبسط في قاع المحيط لا تحدث عنده أيّ ظاهرة"},{"id":"d","text":"منطقة تلتصق فيها القارّات"}]'::jsonb, 'b', 'الظهرة المحيطية سلسلة جبلية بركانية ضخمة وسط المحيط، تتباعد عندها صفيحتان وتتكوّن قشرة محيطية جديدة. الخيار (أ) يصف منطقة الطمر، والخلط بين الظهرة (تباعد) والطمر (تقارب) خطأ شائع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b5f181f-7691-568b-832f-5686022d61ea', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'ماذا نسمّي ظاهرة تكوّن قشرة محيطية جديدة عند الظهرة؟', '[{"id":"a","text":"الطمر"},{"id":"b","text":"الانجراف القارّي"},{"id":"c","text":"التوسّع المحيطي"},{"id":"d","text":"الكسوف"}]'::jsonb, 'c', 'صعود الصهير عند الظهرة وبرودته لتكوين قشرة محيطية جديدة يُسمّى التوسّع المحيطي. ويقابله الطمر حيث تختفي القشرة لا حيث تتكوّن.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8068efa4-e469-5eb0-9409-5cf569cfbbf2', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'منطقة الطمر (الاندساس) هي حدود:', '[{"id":"a","text":"متباعدة تتكوّن عندها قشرة جديدة"},{"id":"b","text":"متقاربة تغوص عندها صفيحة محيطية داخل الوشاح"},{"id":"c","text":"ثابتة لا تتحرّك"},{"id":"d","text":"تلتقي عندها صفيحتان قارّيتان لتكوّنا محيطًا جديدًا"}]'::jsonb, 'b', 'منطقة الطمر حدود متقاربة: تغوص عندها الصفيحة المحيطية الأكثر كثافة تحت أخرى داخل الوشاح. الخيار (أ) يصف الظهرة وهي عكس الطمر تمامًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b09492a-988c-5031-ba29-1fe95b154e2d', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'أيّ ممّا يلي ليس من أدلّة فاجنر على انجراف القارّات؟', '[{"id":"a","text":"تطابق سواحل القارّات كأحجية"},{"id":"b","text":"وجود متحجّرات مشتركة على قارّات متباعدة"},{"id":"c","text":"تواصل السلاسل الجبلية والصخور بين القارّات"},{"id":"d","text":"تشابه أشكال السحب فوق القارّات"}]'::jsonb, 'd', 'اعتمد فاجنر على تطابق السواحل والمتحجّرات المشتركة وتواصل الصخور والجبال. أمّا أشكال السحب فلا علاقة لها بالأمر، فهي ظاهرة جوّية متغيّرة وليست دليلًا جيولوجيًّا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('274994e8-1a05-534c-bd0a-8ba589130e88', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'كيف يتغيّر عمر القشرة المحيطية كلّما ابتعدنا عن الظهرة؟', '[{"id":"a","text":"تصبح أحدث"},{"id":"b","text":"تصبح أقدم"},{"id":"c","text":"لا يتغيّر عمرها"},{"id":"d","text":"تختفي تمامًا"}]'::jsonb, 'b', 'بما أنّ القشرة الجديدة تتكوّن باستمرار عند الظهرة وتُدفع جانبًا، فإنّ القشرة تكون أحدث عند الظهرة وتزداد قِدمًا كلّما ابتعدنا عنها. هذا من أهمّ أدلّة التوسّع المحيطي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b15c44ff-4c11-543e-adec-f46d530e26e7', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'ماذا يصاحب منطقة الطمر عادةً؟', '[{"id":"a","text":"خنادق محيطية عميقة وبراكين وزلازل قويّة"},{"id":"b","text":"اختفاء كامل للزلازل والبراكين"},{"id":"c","text":"تكوّن قشرة محيطية جديدة فقط"},{"id":"d","text":"توقّف حركة الصفائح"}]'::jsonb, 'a', 'يصاحب الطمر تكوّن خنادق محيطية عميقة، وبراكين وسلاسل جبلية، وزلازل قويّة عميقة بسبب احتكاك الصفيحة الغائصة. تكوّن القشرة الجديدة يحدث عند الظهرة لا عند الطمر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
