INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6886374-5cdb-5955-89b9-4ad9b2b46759', '18baf7c2-8131-5080-bd1d-7995d53194db', 'صفيحة تحمل قشرة محيطية اقتربت من صفيحة تحمل قشرة قارّية. ماذا يحدث عند الحدّ بينهما؟', '[{"id":"a","text":"تغوص القشرة المحيطية الأكثر كثافة تحت القارّية (طمر)"},{"id":"b","text":"تغوص القشرة القارّية تحت المحيطية لأنّها أخفّ"},{"id":"c","text":"تتباعد الصفيحتان وتتكوّن ظهرة"},{"id":"d","text":"تتوقّف الصفيحتان دون أيّ ظاهرة"}]'::jsonb, 'a', 'عند تقارب قشرة محيطية مع قارّية، تغوص المحيطية لأنّها أكثر كثافة (طمر). الخيار (ب) يعكس العلاقة، والخيار (ج) يصف حدًّا متباعدًا لا متقاربًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58ff1f8a-787e-504e-81d3-09e279f4891e', '18baf7c2-8131-5080-bd1d-7995d53194db', 'وُجدت متحجّرات لنبات بَرّي واحد على سواحل إفريقيا وأمريكا الجنوبية معًا. ما أفضل تفسير لذلك؟', '[{"id":"a","text":"النبات عبر المحيط سباحةً"},{"id":"b","text":"القارّتان كانتا ملتصقتين ثمّ تباعدتا بانجراف القارّات"},{"id":"c","text":"صدفة لا معنى لها"},{"id":"d","text":"البذور حملتها الرياح عبر المحيط الأطلسي"}]'::jsonb, 'b', 'وجود المتحجّرات نفسها على قارّتين يفصلهما محيط اليوم دليل على أنّهما كانتا ملتصقتين (بانجيا) ثمّ تباعدتا، وهو جوهر استدلال فاجنر. النبات البرّي لا يعبر محيطًا سباحةً.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('266130a5-b359-5c2a-b3df-8aa6cf93fab9', '18baf7c2-8131-5080-bd1d-7995d53194db', 'لماذا تتركّز البراكين والزلازل العنيفة حول المحيط الهادئ («حزام النار»)؟', '[{"id":"a","text":"لأنّ مياهه أكثر سخونة"},{"id":"b","text":"لأنّه محاط بحدود صفائح ومناطق طمر نشطة"},{"id":"c","text":"لأنّه أبعد المحيطات عن الشمس"},{"id":"d","text":"لأنّ قاعه يخلو من الصفائح"}]'::jsonb, 'b', 'حزام النار يحيط بالمحيط الهادئ حيث تتعدّد حدود الصفائح ومناطق الطمر النشطة، فتتركّز عندها البراكين والزلازل العنيفة. سبب التركّز هو حركة الصفائح عند حدودها لا حرارة الماء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac6eed8d-e95d-5ce2-b65c-aa980c76d370', '18baf7c2-8131-5080-bd1d-7995d53194db', 'لماذا توصف القشرة المحيطية بأنّها «تتجدّد» باستمرار رغم قِدم الأرض؟', '[{"id":"a","text":"لأنّها تُنتَج عند الظهرات وتُستهلَك عند مناطق الطمر"},{"id":"b","text":"لأنّها لا تتحرّك إطلاقًا"},{"id":"c","text":"لأنّ الزلازل تكوّنها من جديد"},{"id":"d","text":"لأنّ القارّات تتحوّل إلى قشرة محيطية"}]'::jsonb, 'a', 'تُنتَج القشرة المحيطية عند الظهرات (توسّع محيطي) وتختفي داخل الوشاح عند مناطق الطمر، فتبقى أحدث بكثير من القشرة القارّية. هذا التوازن بين الإنتاج والاستهلاك يفسّر تجدّدها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6e89736-fa69-59bc-a679-16a09dfedc24', '18baf7c2-8131-5080-bd1d-7995d53194db', 'إذا اقتربت صفيحتان قارّيتان (كلاهما قشرة قارّية أخفّ)، فالنتيجة الأرجح:', '[{"id":"a","text":"غوص إحداهما بسهولة في الوشاح"},{"id":"b","text":"تصادم يرفع سلاسل جبلية ضخمة"},{"id":"c","text":"تكوّن ظهرة محيطية بينهما"},{"id":"d","text":"اختفاء القارّتين كليًّا"}]'::jsonb, 'b', 'لأنّ القشرة القارّية خفيفة لا تغوص بسهولة، يؤدّي تصادم صفيحتين قارّيتين إلى رفع وتجعّد القشرة وتكوّن سلاسل جبلية ضخمة (مثل جبال الهملايا). الطمر السهل يحدث للقشرة المحيطية الأكثر كثافة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46270910-933b-5fee-be14-d078c48d0500', '18baf7c2-8131-5080-bd1d-7995d53194db', 'ما العنصر الذي عجز فاجنر عن تفسيره، وفسّرته لاحقًا نظرية تكتونية الصفائح؟', '[{"id":"a","text":"شكل القارّات"},{"id":"b","text":"وجود المتحجّرات"},{"id":"c","text":"القوّة المحرّكة التي تجعل القارّات تنجرف"},{"id":"d","text":"وجود المحيطات"}]'::jsonb, 'c', 'قدّم فاجنر أدلّة قويّة على الانجراف لكنّه لم يستطع تفسير محرّكه، فرُفضت نظريته في البداية. لاحقًا فسّرت تكتونية الصفائح المحرّك بتيّارات الحمل الحراري في الوشاح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', '19515433-2bba-541b-9762-67c03842195a', 'sciences-vie-terre', '👑 تحدّي النخبة: تكتونية الصفائح — تحليل ووضعيات', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35b85bd7-db2d-52e0-97c9-bb92e19322c2', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'قال تلميذ: «الصفيحة التكتونية هي القشرة الأرضية وحدها». ما تصحيح هذه العبارة؟', '[{"id":"a","text":"العبارة صحيحة تمامًا"},{"id":"b","text":"الصفيحة هي الوشاح كلّه"},{"id":"c","text":"الصفيحة جزء من الليثوسفير: القشرة + أعلى الوشاح الصلب"},{"id":"d","text":"الصفيحة هي الأسثينوسفير اللزج"}]'::jsonb, 'c', 'الصفيحة قطعة من الليثوسفير، أي القشرة مضافًا إليها الجزء العلوي الصلب من الوشاح، وليست القشرة وحدها. الخلط بين «الصفيحة» و«القشرة» خطأ شائع جدًّا، كما أنّ الأسثينوسفير لزج وليس جزءًا من الصفيحة الصلبة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d88457b-ad82-5e6d-b3e5-e7489d611bfb', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'قاس باحث عمر القشرة المحيطية على جانبَي ظهرة فوجده يزداد بانتظام نحو الخارج على الجانبين. ما الاستنتاج الأدقّ؟', '[{"id":"a","text":"القشرة تتكوّن عند الظهرة وتنفصل عنها على الجانبين (توسّع محيطي متماثل)"},{"id":"b","text":"القشرة تغوص عند الظهرة"},{"id":"c","text":"الظهرة تستهلك القشرة القديمة"},{"id":"d","text":"عمر القشرة لا علاقة له بالظهرة"}]'::jsonb, 'a', 'ازدياد العمر بانتظام وبتماثل على الجانبين دليل على أنّ القشرة الجديدة تتكوّن عند محور الظهرة وتُدفع نحو الجانبين، أي توسّع محيطي متماثل. الظهرة تُنتج القشرة ولا تستهلكها (الاستهلاك يحدث عند الطمر).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d20538bc-6d99-5c48-a2f0-a7e4e2a91c64', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'تتقارب صفيحتان محيطيتان متساويتا الكثافة تقريبًا. أيّ نتيجة أكثر اتّساقًا مع آليّة الطمر؟', '[{"id":"a","text":"لا يحدث أيّ طمر إطلاقًا لأنّ الكثافتين متساويتان"},{"id":"b","text":"تغوص الصفيحة الأقدم (الأبرد والأكثر كثافة) تحت الأحدث"},{"id":"c","text":"تصعد الصفيحتان معًا وتكوّنان قارّة"},{"id":"d","text":"تتحوّل القشرة المحيطية إلى قارّية فورًا"}]'::jsonb, 'b', 'تزداد كثافة القشرة المحيطية مع تقادمها وبرودتها، فتغوص الصفيحة الأقدم (الأكثر كثافة) تحت الأحدث. فالطمر لا يتطلّب وجود قشرة قارّية، بل فرقًا في الكثافة قد ينشأ من فرق العمر/الحرارة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c1168cc-06f8-5fff-9a7d-fdb3b0fb65cc', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'في خريطة لتوزيع الزلازل، ظهرت بؤرها سطحيةً عند ظهرة محيطية، وعميقةً متدرّجةً مائلةً تحت قارّة مجاورة. كيف نفسّر ذلك؟', '[{"id":"a","text":"البؤر السطحية مرتبطة بالتباعد عند الظهرة، والعميقة المائلة برحلة الصفيحة الغائصة في الطمر"},{"id":"b","text":"كلّ الزلازل سطحية دائمًا"},{"id":"c","text":"البؤر العميقة سببها رياح سطحية"},{"id":"d","text":"لا علاقة بين عمق البؤر وحدود الصفائح"}]'::jsonb, 'a', 'عند الظهرة (تباعد) تكون البؤر سطحيةً، أمّا عند الطمر فتترتّب البؤر على مستوٍ مائل يزداد عمقًا مع غوص الصفيحة داخل الوشاح. هذا التوزيع المائل للبؤر العميقة من أقوى الأدلّة على الطمر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('594633b4-9cdd-5d32-a408-1f3e35569cc3', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'لماذا لا يكفي تطابق سواحل القارّات وحده لإثبات الانجراف، فاحتاج فاجنر إلى أدلّة أخرى؟', '[{"id":"a","text":"لأنّ التطابق الشكلي قد يكون صدفة، فعزّزه بالمتحجّرات وتواصل الصخور والجبال"},{"id":"b","text":"لأنّ السواحل لا تتطابق أصلًا"},{"id":"c","text":"لأنّ التطابق الشكلي وحده يكفي تمامًا"},{"id":"d","text":"لأنّ المتحجّرات تنفي الانجراف"}]'::jsonb, 'a', 'التطابق الشكلي مؤشّر لكنّه قد يُفسَّر بالصدفة، لذلك دعّمه فاجنر بأدلّة مستقلّة: متحجّرات مشتركة وتواصل صخور وسلاسل جبلية بين القارّات. تضافر أدلّة من مصادر مختلفة يقوّي الاستنتاج العلمي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('318810fa-5b8a-5549-b3f1-a7578f3d322e', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'وضعية تركيبية: محيط تتوسّع ظهرته باستمرار بينما إحدى حوافّه منطقة طمر نشطة. ماذا يحدث لمساحة هذا المحيط على المدى الطويل إذا كان معدّل الطمر أكبر من معدّل التوسّع؟', '[{"id":"a","text":"تتقلّص مساحة المحيط لأنّ ما يُستهلَك عند الطمر أكبر ممّا يُنتَج عند الظهرة"},{"id":"b","text":"تتّسع مساحة المحيط حتمًا"},{"id":"c","text":"تبقى المساحة ثابتة دائمًا مهما كانت المعدّلات"},{"id":"d","text":"يختفي المحيط فورًا في لحظة واحدة"}]'::jsonb, 'a', 'مساحة المحيط محصّلة بين الإنتاج عند الظهرة والاستهلاك عند الطمر. إذا فاق معدّل الطمر معدّل التوسّع، تغلب خسارة القشرة على إنتاجها فتتقلّص مساحة المحيط تدريجيًّا (لا فورًا). هذا يفسّر انغلاق محيطات قديمة عبر العصور الجيولوجية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

